// лӘЁл“  м—°мӮ°мқҖ ndarray нҳ•нғң
type Tensor = Float64Array  // в„қ^n
type Matrix = Float64Array  // в„қ^(mГ—n)
type Tensor3D = Float64Array // в„қ^(d1Г—d2Г—d3)

// м—°мӮ°л“Ө
class TensorOps {
  // кё°ліё м—°мӮ°
  dot(a: Tensor, b: Tensor): number  // <a,b> inner product
  matmul(A: Matrix, B: Matrix): Matrix  // A @ B
  outer(a: Tensor, b: Tensor): Matrix  // a вҠ— b

  // кі кёү м—°мӮ°
  contract(t1: Tensor3D, t2: Tensor3D, indices): Tensor  // tensor contraction
  einsum(expr: string, ...tensors): Tensor  // Einstein summation

  // нҷңм„ұнҷ” н•ЁмҲҳ (as differentiable maps)
  relu(x: Tensor): Tensor  // max(0, x)
  sigmoid(x: Tensor): Tensor  // 1/(1+exp(-x))
  softmax(x: Tensor, tau: number): Tensor  // exp(x/П„) / ОЈexp(x/П„)

  // к·ёлһҳл””м–ёнҠё
  grad_relu(grad: Tensor, x: Tensor): Tensor
  grad_sigmoid(grad: Tensor, y: Tensor): Tensor
  grad_softmax(grad: Tensor, y: Tensor): Tensor
}
```

