class EnsembleModule {
  f_weight: Function  // в„қ^768 вҶ’ в„қ^3, query вҶ’ weights

  compute_weights(q: Tensor): Tensor {
    // w = softmax(f_weight(q))
    // w вҲҲ О”^2 (simplex)
    return softmax(f_weight(q), tau=0.8)
  }

  combine(w: Tensor, z_a: Tensor, z_b: Tensor, z_c: Tensor): Tensor {
    // e = w[0]В·z_a + w[1]В·z_b + w[2]В·z_c
    // e вҲҲ в„қ^256
    return add(
      scale(z_a, w[0]),
      scale(z_b, w[1]),
      scale(z_c, w[2])
    )
  }

  gradient(grad_e: Tensor, w: Tensor, paths): {dw, dz_a, dz_b, dz_c} { ... }
}
```

### 5. critique.ts (400мӨ„)
