class CritiqueModule {
  L: Function  // Loss function

  critique(ensemble: Tensor, query: Tensor): {grad, confidence} {
    // Оҙ = вҲҮ_ensemble L(ensemble, query)
    const grad = compute_gradient(this.L, ensemble)  // вҲӮL/вҲӮensemble

    // confidence = 1 - ||grad||_2 / max_grad
    const norm = l2_norm(grad)
    const confidence = Math.max(0, 1 - norm / 10)

    return {grad, confidence}
  }
}
```

### 6. sampler.ts (300мӨ„)
мғҳн”Ңл§Ғ (softmax + мһ„кі„к°’)

