class Sampler {
  W_out: Matrix  // в„қ^(256Г—vocab)
  b_out: Tensor

  sample(ensemble: Tensor, tau: number, threshold: number): {token, prob} {
    // logits = W_out @ ensemble + b_out
    const logits = add(matmul(W_out, ensemble), b_out)

    // p = softmax(logits / П„)
    const probs = softmax(scale(logits, 1/tau))

    // if max(p) > Оё: return argmax
    if (max(probs) > threshold) {
      return {token: argmax(probs), prob: max(probs)}
    }
    // else: sample from p
    return {token: multinomial_sample(probs), prob: probs[token]}
  }
}
```

