### 8. runtime.ts (400мӨ„)
PostMindLang лҹ°нғҖмһ„

```typescript
class PostMindLangRuntime {
  encoder: QueryEncoder
  paths: PathExecutor
  ensemble: EnsembleModule
  critique: CritiqueModule
  sampler: Sampler
  diff_ops: DifferentiableOps

  async execute(q: Tensor): Promise<ExecutionResult> {
    // 1. Encode
    const z = this.encoder.encode(q)

    // 2. Fork 3 paths
    const {z_a, z_b, z_c} = this.paths.execute_parallel(z)

    // 3. Adaptive weights
    const w = this.ensemble.compute_weights(q)

    // 4. Ensemble
    const e = this.ensemble.combine(w, z_a, z_b, z_c)

    // 5. Critique
    const {grad, confidence} = this.critique.critique(e, q)

    // 6. Sample
    if (confidence > 0.8) {
      return this.sampler.sample(e, 0.8, 0.9)
    } else {
      return await this.refine(q, grad)
    }
  }

  // м „мІҙ к·ёлһҳл””м–ёнҠё кі„мӮ° (нӣҲл Ёмҡ©)
  backward(loss: number) {
    return this.diff_ops.backward(loss)
  }
}
```

