/**
 * PostMindLang Runtime: Pure Tensor Operations
 * мҲңмҲҳ лІЎн„°/н–үл ¬/н…җм„ң м—°мӮ° лӘЁл“Ҳ
 * лӘЁл“  м—°мӮ°мқҖ м„ нҳ•лҢҖмҲҳ(Linear Algebra) кё°л°ҳ
 */

export type Tensor = Float64Array; // в„қ^n
export type Matrix = Float64Array; // в„қ^(mГ—n) flattened
export type Tensor3D = Float64Array; // в„қ^(d1Г—d2Г—d3) flattened

/**
 * Tensor л©”нғҖлҚ°мқҙн„° - shape м •ліҙ м ҖмһҘ
 */
export interface TensorShape {
  dims: number[];
  size: number;
}

/**
 * н…җм„ң мғқм„ұ л°Ҹ кё°ліё м—°мӮ°
 */
export class TensorOps {
  /**
   * 1D н…җм„ң мғқм„ұ
   */
  static zeros(n: number): Tensor {
    return new Float64Array(n);
  }

  /**
   * 1D н…җм„ңлҘј мһ„мқҳмқҳ к°’мңјлЎң мғқм„ұ
   */
  static fill(n: number, value: number): Tensor {
    const t = new Float64Array(n);
    t.fill(value);
    return t;
  }

  /**
   * 1D н…җм„ңлҘј лӮңмҲҳлЎң мҙҲкё°нҷ” (Gaussian)
   */
  static randn(n: number, seed?: number): Tensor {
    const t = new Float64Array(n);
    const rng = seed !== undefined ? this.seededRandom(seed) : Math.random;
    for (let i = 0; i < n; i++) {
      // Box-Muller ліҖнҷҳ: к· л“ұл¶„нҸ¬ вҶ’ м •к·ңл¶„нҸ¬
      const u1 = rng();
      const u2 = rng();
      t[i] = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
    }
    return t;
  }

  /**
   * мӢңл“ң кё°л°ҳ лӮңмҲҳ мғқм„ұкё°
   */
  private static seededRandom(seed: number) {
    return () => {
      seed = (seed * 9301 + 49297) % 233280;
      return seed / 233280;
    };
  }

  /**
   * н–үл ¬ мғқм„ұ (m Г— n)
   */
  static matrix(m: number, n: number, init?: (i: number, j: number) => number): Matrix {
    const M = new Float64Array(m * n);
    if (init) {
      for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
          M[i * n + j] = init(i, j);
        }
      }
    }
    return M;
  }

  /**
   * лӢЁмң„ н–үл ¬ мғқм„ұ
   */
  static eye(n: number): Matrix {
    return this.matrix(n, n, (i, j) => (i === j ? 1 : 0));
  }

  /**
   * лӮҙм Ғ (dot product): <a, b> = ОЈ a_i * b_i
   */
  static dot(a: Tensor, b: Tensor): number {
    if (a.length !== b.length) {
      throw new Error(`Dimension mismatch: ${a.length} vs ${b.length}`);
    }
    let result = 0;
    for (let i = 0; i < a.length; i++) {
      result += a[i] * b[i];
    }
    return result;
  }

  /**
   * L2 л…ёлҰ„: ||a||_2 = вҲҡ(ОЈ a_iВІ)
   */
  static l2_norm(a: Tensor): number {
    return Math.sqrt(this.dot(a, a));
  }

  /**
   * L1 л…ёлҰ„: ||a||_1 = ОЈ |a_i|
   */
  static l1_norm(a: Tensor): number {
    let result = 0;
    for (let i = 0; i < a.length; i++) {
      result += Math.abs(a[i]);
    }
    return result;
  }

  /**
   * мөңлҢҖ л…ёлҰ„: ||a||_вҲһ = max |a_i|
   */
  static max_norm(a: Tensor): number {
    let result = 0;
    for (let i = 0; i < a.length; i++) {
      result = Math.max(result, Math.abs(a[i]));
    }
    return result;
  }

  /**
   * лІЎн„° лҚ§м…Ҳ: c = a + b
   */
  static add(a: Tensor, b: Tensor): Tensor {
    if (a.length !== b.length) {
      throw new Error(`Dimension mismatch: ${a.length} vs ${b.length}`);
    }
    const c = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      c[i] = a[i] + b[i];
    }
    return c;
  }

  /**
   * лІЎн„° лә„м…Ҳ: c = a - b
   */
  static subtract(a: Tensor, b: Tensor): Tensor {
    if (a.length !== b.length) {
      throw new Error(`Dimension mismatch: ${a.length} vs ${b.length}`);
    }
    const c = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      c[i] = a[i] - b[i];
    }
    return c;
  }

  /**
   * мҠӨм№јлқј кіұм…Ҳ: b = Оұ * a
   */
  static scale(a: Tensor, alpha: number): Tensor {
    const b = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      b[i] = a[i] * alpha;
    }
    return b;
  }

  /**
   * мӣҗмҶҢлі„ кіұм…Ҳ (Hadamard product): c = a вҠҷ b
   */
  static elementwise_mult(a: Tensor, b: Tensor): Tensor {
    if (a.length !== b.length) {
      throw new Error(`Dimension mismatch: ${a.length} vs ${b.length}`);
    }
    const c = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      c[i] = a[i] * b[i];
    }
    return c;
  }

  /**
   * мӣҗмҶҢлі„ лӮҳлҲ—м…Ҳ: c = a Г· b (element-wise)
   */
  static elementwise_div(a: Tensor, b: Tensor): Tensor {
    if (a.length !== b.length) {
      throw new Error(`Dimension mismatch: ${a.length} vs ${b.length}`);
    }
    const c = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      c[i] = a[i] / b[i];
    }
    return c;
  }

  /**
   * мҷём Ғ (outer product): C = a вҠ— b, C вҲҲ в„қ^(mГ—n)
   * flattened: C[i*n + j] = a[i] * b[j]
   */
  static outer(a: Tensor, b: Tensor): Matrix {
    const m = a.length;
    const n = b.length;
    const C = new Float64Array(m * n);
    for (let i = 0; i < m; i++) {
      for (let j = 0; j < n; j++) {
        C[i * n + j] = a[i] * b[j];
      }
    }
    return C;
  }

  /**
   * н–үл ¬-лІЎн„° кіұм…Ҳ: b = A @ v
   * A: mГ—n (flattened), v: nГ—1, result: mГ—1
   */
  static matvec(A: Matrix, v: Tensor, m: number, n: number): Tensor {
    if (v.length !== n) {
      throw new Error(`Dimension mismatch: vector length ${v.length} vs matrix width ${n}`);
    }
    const b = new Float64Array(m);
    for (let i = 0; i < m; i++) {
      let sum = 0;
      for (let j = 0; j < n; j++) {
        sum += A[i * n + j] * v[j];
      }
      b[i] = sum;
    }
    return b;
  }

  /**
   * н–үл ¬-н–үл ¬ кіұм…Ҳ: C = A @ B
   * A: mГ—k, B: kГ—n, C: mГ—n
   */
  static matmul(
    A: Matrix,
    B: Matrix,
    m: number,
    k: number,
    n: number
  ): Matrix {
    const C = new Float64Array(m * n);
    for (let i = 0; i < m; i++) {
      for (let j = 0; j < n; j++) {
        let sum = 0;
        for (let p = 0; p < k; p++) {
          sum += A[i * k + p] * B[p * n + j];
        }
        C[i * n + j] = sum;
      }
    }
    return C;
  }

  /**
   * м „м№ҳ (transpose): B = A^T
   * A: mГ—n вҶ’ B: nГ—m
   */
  static transpose(A: Matrix, m: number, n: number): Matrix {
    const B = new Float64Array(n * m);
    for (let i = 0; i < m; i++) {
      for (let j = 0; j < n; j++) {
        B[j * m + i] = A[i * n + j];
      }
    }
    return B;
  }

  /**
   * л°°м№ҳ н–үл ¬-лІЎн„° кіұм…Ҳ: V = Q @ A (к°Ғ н–үкіј Aмқҳ кіұ)
   * Q: batch_size Г— k (к°Ғ н–үмқҙ лІЎн„°)
   * A: k Г— n
   * V: batch_size Г— n
   */
  static matmul_batch(
    Q: Matrix,
    A: Matrix,
    batch_size: number,
    k: number,
    n: number
  ): Matrix {
    const V = new Float64Array(batch_size * n);
    for (let b = 0; b < batch_size; b++) {
      for (let j = 0; j < n; j++) {
        let sum = 0;
        for (let p = 0; p < k; p++) {
          sum += Q[b * k + p] * A[p * n + j];
        }
        V[b * n + j] = sum;
      }
    }
    return V;
  }

  /**
   * ReLU нҷңм„ұнҷ”: y = max(0, x)
   */
  static relu(x: Tensor): Tensor {
    const y = new Float64Array(x.length);
    for (let i = 0; i < x.length; i++) {
      y[i] = Math.max(0, x[i]);
    }
    return y;
  }

  /**
   * ReLU к·ёлһҳл””м–ёнҠё: вҲӮL/вҲӮx = вҲӮL/вҲӮy * (x > 0 ? 1 : 0)
   */
  static grad_relu(grad_y: Tensor, x: Tensor): Tensor {
    const grad_x = new Float64Array(x.length);
    for (let i = 0; i < x.length; i++) {
      grad_x[i] = x[i] > 0 ? grad_y[i] : 0;
    }
    return grad_x;
  }

  /**
   * Sigmoid нҷңм„ұнҷ”: y = 1 / (1 + exp(-x))
   */
  static sigmoid(x: Tensor): Tensor {
    const y = new Float64Array(x.length);
    for (let i = 0; i < x.length; i++) {
      y[i] = 1 / (1 + Math.exp(-x[i]));
    }
    return y;
  }

  /**
   * Sigmoid к·ёлһҳл””м–ёнҠё: вҲӮL/вҲӮx = вҲӮL/вҲӮy * y * (1 - y)
   */
  static grad_sigmoid(grad_y: Tensor, y: Tensor): Tensor {
    const grad_x = new Float64Array(y.length);
    for (let i = 0; i < y.length; i++) {
      grad_x[i] = grad_y[i] * y[i] * (1 - y[i]);
    }
    return grad_x;
  }

  /**
   * Softmax нҷңм„ұнҷ”: y_i = exp(x_i / П„) / ОЈ exp(x_j / П„)
   */
  static softmax(x: Tensor, tau: number = 1.0): Tensor {
    // мҲҳм№ҳ м•Ҳм •м„ұмқ„ мң„н•ҙ мөңлҢ“к°’ л№јкё°
    let max_x = x[0];
    for (let i = 1; i < x.length; i++) {
      max_x = Math.max(max_x, x[i]);
    }

    const y = new Float64Array(x.length);
    let sum = 0;
    for (let i = 0; i < x.length; i++) {
      const exp_val = Math.exp((x[i] - max_x) / tau);
      y[i] = exp_val;
      sum += exp_val;
    }

    for (let i = 0; i < y.length; i++) {
      y[i] /= sum;
    }
    return y;
  }

  /**
   * Softmax к·ёлһҳл””м–ёнҠё: вҲӮL/вҲӮx_i = вҲӮL/вҲӮy_i * (y_i - y_i * ОЈ y_j * вҲӮL/вҲӮy_j)
   */
  static grad_softmax(grad_y: Tensor, y: Tensor): Tensor {
    const grad_x = new Float64Array(y.length);
    let sum = 0;
    for (let i = 0; i < y.length; i++) {
      sum += grad_y[i] * y[i];
    }
    for (let i = 0; i < y.length; i++) {
      grad_x[i] = y[i] * (grad_y[i] - sum);
    }
    return grad_x;
  }

  /**
   * н…җм„ң м¶•м•Ҫ (Tensor Contraction)
   * л‘җ н…җм„ңмқҳ м§Җм •лҗң мқёлҚұмҠӨм—җ лҢҖн•ҙ лӮҙм Ғ мҲҳн–ү
   */
  static contract(
    t1: Tensor,
    t2: Tensor,
    shape1: number[],
    shape2: number[],
    indices1: number[],
    indices2: number[]
  ): Tensor {
    // к°„лӢЁн•ң кө¬нҳ„: 1DмҷҖ 2Dл§Ң м§Җмӣҗ
    if (shape1.length === 1 && shape2.length === 1) {
      // л‘җ лІЎн„°мқҳ лӮҙм Ғ
      return this.fill(1, this.dot(t1, t2));
    }
    throw new Error("Complex tensor contraction not yet implemented");
  }

  /**
   * мөңлҢ“к°’ мӣҗмҶҢ
   */
  static max(a: Tensor): number {
    let max_val = a[0];
    for (let i = 1; i < a.length; i++) {
      max_val = Math.max(max_val, a[i]);
    }
    return max_val;
  }

  /**
   * мөңлҢ“к°’ мқёлҚұмҠӨ
   */
  static argmax(a: Tensor): number {
    let max_idx = 0;
    let max_val = a[0];
    for (let i = 1; i < a.length; i++) {
      if (a[i] > max_val) {
        max_val = a[i];
        max_idx = i;
      }
    }
    return max_idx;
  }

  /**
   * н•©кі„
   */
  static sum(a: Tensor): number {
    let sum = 0;
    for (let i = 0; i < a.length; i++) {
      sum += a[i];
    }
    return sum;
  }

  /**
   * нҸүк· 
   */
  static mean(a: Tensor): number {
    return this.sum(a) / a.length;
  }

  /**
   * н‘ңмӨҖнҺём°Ё
   */
  static std(a: Tensor): number {
    const m = this.mean(a);
    let sum_sq = 0;
    for (let i = 0; i < a.length; i++) {
      sum_sq += (a[i] - m) * (a[i] - m);
    }
    return Math.sqrt(sum_sq / a.length);
  }

  /**
   * м •к·ңнҷ” (normalization): x_norm = (x - mean) / std
   */
  static normalize(a: Tensor): Tensor {
    const mean = this.mean(a);
    const std = this.std(a);
    const b = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      b[i] = (a[i] - mean) / (std + 1e-8);
    }
    return b;
  }

  /**
   * Exp н•ЁмҲҳ (element-wise)
   */
  static exp(x: Tensor): Tensor {
    const y = new Float64Array(x.length);
    for (let i = 0; i < x.length; i++) {
      y[i] = Math.exp(x[i]);
    }
    return y;
  }

  /**
   * Log н•ЁмҲҳ (element-wise)
   */
  static log(x: Tensor): Tensor {
    const y = new Float64Array(x.length);
    for (let i = 0; i < x.length; i++) {
      y[i] = Math.log(x[i]);
    }
    return y;
  }

  /**
   * м ҲлҢ“к°’ (element-wise)
   */
  static abs(x: Tensor): Tensor {
    const y = new Float64Array(x.length);
    for (let i = 0; i < x.length; i++) {
      y[i] = Math.abs(x[i]);
    }
    return y;
  }

  /**
   * ліөмӮ¬
   */
  static copy(a: Tensor): Tensor {
    return new Float64Array(a);
  }

  /**
   * нҒҙлҰ¬н•‘: clamp(x, min, max)
   */
  static clip(a: Tensor, min: number, max: number): Tensor {
    const b = new Float64Array(a.length);
    for (let i = 0; i < a.length; i++) {
      b[i] = Math.max(min, Math.min(max, a[i]));
    }
    return b;
  }

  /**
   * н…җм„ң лҚӨн”„ (л””лІ„к№…мҡ©)
   */
  static dump(a: Tensor, name: string = "Tensor", limit: number = 10): string {
    const vals = Array.from(a.slice(0, limit)).map((v) => v.toFixed(4));
    const suffix = a.length > limit ? `... (${a.length} total)` : "";
    return `${name}: [${vals.join(", ")}]${suffix}`;
  }

  /**
   * кё°мҡёкё° кІҖмӮ¬ (numerical gradient verification)
   */
  static checkGradient(
    fn: (x: Tensor) => number,
    grad_fn: (x: Tensor) => Tensor,
    x: Tensor,
    eps: number = 1e-5
  ): number {
    const grad_analytical = grad_fn(x);
    let max_diff = 0;

    for (let i = 0; i < x.length; i++) {
      const x_plus = this.copy(x);
      const x_minus = this.copy(x);
      x_plus[i] += eps;
      x_minus[i] -= eps;

      const grad_numerical =
        (fn(x_plus) - fn(x_minus)) / (2 * eps);
      const diff = Math.abs(grad_analytical[i] - grad_numerical);
      max_diff = Math.max(max_diff, diff);
    }

    return max_diff;
  }
}

/**
 * лӢӨмӨ‘м„ нҳ• м—°мӮ° (Multilinear Operations)
 */
export class MultilinearOps {
  /**
   * лӢӨм„ нҳ• нҳ•нғң (bilinear form): L(x, y) = x^T @ A @ y
   */
  static bilinear_form(x: Tensor, A: Matrix, y: Tensor, n: number, m: number): number {
    // лЁјм Җ A @ y кі„мӮ°
    const Ay = TensorOps.matvec(A, y, n, m);
    // к·ё лӢӨмқҢ x^T @ (A @ y) кі„мӮ°
    return TensorOps.dot(x, Ay);
  }

  /**
   * лӢӨм„ нҳ• нҳ•нғңмқҳ к·ёлһҳл””м–ёнҠё w.r.t. x: вҲӮL/вҲӮx = A @ y
   */
  static grad_bilinear_x(A: Matrix, y: Tensor, n: number, m: number): Tensor {
    return TensorOps.matvec(A, y, n, m);
  }

  /**
   * лӢӨм„ нҳ• нҳ•нғңмқҳ к·ёлһҳл””м–ёнҠё w.r.t. y: вҲӮL/вҲӮy = A^T @ x
   */
  static grad_bilinear_y(
    A: Matrix,
    x: Tensor,
    n: number,
    m: number
  ): Tensor {
    const AT = TensorOps.transpose(A, n, m);
    return TensorOps.matvec(AT, x, m, n);
  }
}

/**
 * PostMindLang Runtime: Query Encoding
 * мҝјлҰ¬ мқёмҪ”л”© лӘЁл“Ҳ: E: в„қ^768 вҶ’ в„қ^512
 */

import { Tensor, Matrix, TensorOps } from "./tensor";

/**
 * мҝјлҰ¬ мқёмҪ”лҚ”
 * м„ нҳ• ліҖнҷҳ + нҺён–Ҙ: z = W^T @ q + b
 */
export class QueryEncoder {
  /**
   * к°ҖмӨ‘м№ҳ н–үл ¬: W вҲҲ в„қ^(768Г—512)
   * м ҖмһҘ: flattened (768 * 512 = 393216 elements)
   */
  W: Matrix;

  /**
   * нҺён–Ҙ: b вҲҲ в„қ^512
   */
  b: Tensor;

  /**
   * мһ…л Ҙ м°Ёмӣҗ
   */
  input_dim: number;

  /**
   * м¶ңл Ҙ м°Ёмӣҗ
   */
  output_dim: number;

  constructor(input_dim: number = 768, output_dim: number = 512) {
    this.input_dim = input_dim;
    this.output_dim = output_dim;

    // He мҙҲкё°нҷ”: W ~ N(0, sqrt(2/input_dim))
    const scale = Math.sqrt(2.0 / input_dim);
    this.W = TensorOps.randn(input_dim * output_dim);
    for (let i = 0; i < this.W.length; i++) {
      this.W[i] *= scale;
    }

    // нҺён–Ҙ мҙҲкё°нҷ”: b = 0
    this.b = TensorOps.zeros(output_dim);
  }

  /**
   * лӢЁмқј мҝјлҰ¬ мқёмҪ”л”©: z = W^T @ q + b
   * q вҲҲ в„қ^768 вҶ’ z вҲҲ в„қ^512
   */
  encode(q: Tensor): Tensor {
    if (q.length !== this.input_dim) {
      throw new Error(
        `Query dimension mismatch: ${q.length} vs ${this.input_dim}`
      );
    }

    // 1. W^T @ q: (768Г—512)^T @ 768 = 512Г—768 @ 768 = 512
    const WT = TensorOps.transpose(this.W, this.input_dim, this.output_dim);
    const z_linear = TensorOps.matvec(WT, q, this.output_dim, this.input_dim);

    // 2. z = z_linear + b
    const z = TensorOps.add(z_linear, this.b);
    return z;
  }

  /**
   * л°°м№ҳ мҝјлҰ¬ мқёмҪ”л”©: Z = Q @ W + b (vectorized)
   * Q вҲҲ в„қ^(batch_sizeГ—768) вҶ’ Z вҲҲ в„қ^(batch_sizeГ—512)
   */
  encode_batch(Q: Matrix, batch_size: number): Matrix {
    if (Q.length !== batch_size * this.input_dim) {
      throw new Error(
        `Batch query dimension mismatch: ${Q.length} vs ${
          batch_size * this.input_dim
        }`
      );
    }

    // Z = Q @ W (batch_size Г— 768) @ (768 Г— 512) = batch_size Г— 512
    const Z = TensorOps.matmul_batch(
      Q,
      this.W,
      batch_size,
      this.input_dim,
      this.output_dim
    );

    // Z += b (broadcasting: лҚ”н•ҳкё°)
    for (let b = 0; b < batch_size; b++) {
      for (let j = 0; j < this.output_dim; j++) {
        Z[b * this.output_dim + j] += this.b[j];
      }
    }

    return Z;
  }

  /**
   * м „мІҙ к·ёлһҳл””м–ёнҠё кі„мӮ°
   * вҲӮL/вҲӮW, вҲӮL/вҲӮb, вҲӮL/вҲӮq кі„мӮ°
   */
  gradient(
    grad_z: Tensor,
    q: Tensor
  ): { dW: Matrix; db: Tensor; dq: Tensor } {
    if (grad_z.length !== this.output_dim) {
      throw new Error(
        `Gradient dimension mismatch: ${grad_z.length} vs ${this.output_dim}`
      );
    }

    // 1. вҲӮL/вҲӮb = grad_z (м§Ғм ‘ м „нҢҢ)
    const db = TensorOps.copy(grad_z);

    // 2. вҲӮL/вҲӮq = W @ grad_z (chain rule)
    // q вҶҗ W @ grad_zмқёлҚ°, W: 768Г—512, grad_z: 512
    // л”°лқјм„ң вҲӮL/вҲӮq = W @ grad_z (768)
    const dq = TensorOps.matvec(
      this.W,
      grad_z,
      this.input_dim,
      this.output_dim
    );

    // 3. вҲӮL/вҲӮW = q вҠ— grad_z (мҷём Ғ)
    // z_i = ОЈ_j W_ji * q_j + b_i
    // вҲӮL/вҲӮW_ji = вҲӮL/вҲӮz_i * вҲӮz_i/вҲӮW_ji = grad_z_i * q_j
    // flattened: W[i*output_dim + j], gradient: outer(q, grad_z)
    const dW = TensorOps.outer(q, grad_z);

    return { dW, db, dq };
  }

  /**
   * л°°м№ҳ к·ёлһҳл””м–ёнҠё кі„мӮ°
   */
  gradient_batch(
    grad_Z: Matrix,
    Q: Matrix,
    batch_size: number
  ): { dW: Matrix; db: Tensor; dQ: Matrix } {
    if (grad_Z.length !== batch_size * this.output_dim) {
      throw new Error(`Batch gradient dimension mismatch`);
    }

    // 1. вҲӮL/вҲӮb = ОЈ_batch grad_z_b (н•©кі„)
    const db = TensorOps.zeros(this.output_dim);
    for (let b = 0; b < batch_size; b++) {
      for (let j = 0; j < this.output_dim; j++) {
        db[j] += grad_Z[b * this.output_dim + j];
      }
    }

    // 2. вҲӮL/вҲӮQ = grad_Z @ W^T
    const WT = TensorOps.transpose(this.W, this.input_dim, this.output_dim);
    const dQ = TensorOps.matmul_batch(
      grad_Z,
      WT,
      batch_size,
      this.output_dim,
      this.input_dim
    );

    // 3. вҲӮL/вҲӮW = Q^T @ grad_Z
    // Q: batch Г— 768, grad_Z: batch Г— 512
    // к°Ғ л°°м№ҳ bм—җм„ң: dW_b = Q_b вҠ— grad_Z_b
    // м „мІҙ: dW = ОЈ Q_b вҠ— grad_Z_b
    const dW = TensorOps.zeros(this.input_dim * this.output_dim);
    for (let b = 0; b < batch_size; b++) {
      const q_b_start = b * this.input_dim;
      const grad_z_b_start = b * this.output_dim;

      for (let i = 0; i < this.input_dim; i++) {
        for (let j = 0; j < this.output_dim; j++) {
          dW[i * this.output_dim + j] +=
            Q[q_b_start + i] * grad_Z[grad_z_b_start + j];
        }
      }
    }

    return { dW, db, dQ };
  }

  /**
   * к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё (SGD)
   */
  update(dW: Matrix, db: Tensor, learning_rate: number): void {
    // W := W - lr * dW
    for (let i = 0; i < this.W.length; i++) {
      this.W[i] -= learning_rate * dW[i];
    }

    // b := b - lr * db
    for (let i = 0; i < this.b.length; i++) {
      this.b[i] -= learning_rate * db[i];
    }
  }

  /**
   * к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё (Momentum)
   */
  update_momentum(
    dW: Matrix,
    db: Tensor,
    learning_rate: number,
    momentum: number,
    v_W: Matrix,
    v_b: Tensor
  ): void {
    // v_W := momentum * v_W - lr * dW
    for (let i = 0; i < this.W.length; i++) {
      v_W[i] = momentum * v_W[i] - learning_rate * dW[i];
      this.W[i] += v_W[i];
    }

    // v_b := momentum * v_b - lr * db
    for (let i = 0; i < this.b.length; i++) {
      v_b[i] = momentum * v_b[i] - learning_rate * db[i];
      this.b[i] += v_b[i];
    }
  }

  /**
   * к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё (Adam)
   */
  update_adam(
    dW: Matrix,
    db: Tensor,
    learning_rate: number,
    beta1: number,
    beta2: number,
    eps: number,
    t: number,
    m_W: Matrix,
    v_W: Matrix,
    m_b: Tensor,
    v_b: Tensor
  ): void {
    const lr_t = learning_rate * Math.sqrt(1 - Math.pow(beta2, t)) /
      (1 - Math.pow(beta1, t));

    // W м—…лҚ°мқҙнҠё
    for (let i = 0; i < this.W.length; i++) {
      m_W[i] = beta1 * m_W[i] + (1 - beta1) * dW[i];
      v_W[i] = beta2 * v_W[i] + (1 - beta2) * dW[i] * dW[i];
      this.W[i] -= (lr_t * m_W[i]) / (Math.sqrt(v_W[i]) + eps);
    }

    // b м—…лҚ°мқҙнҠё
    for (let i = 0; i < this.b.length; i++) {
      m_b[i] = beta1 * m_b[i] + (1 - beta1) * db[i];
      v_b[i] = beta2 * v_b[i] + (1 - beta2) * db[i] * db[i];
      this.b[i] -= (lr_t * m_b[i]) / (Math.sqrt(v_b[i]) + eps);
    }
  }

  /**
   * L2 м •к·ңнҷ” (weight decay)
   */
  regularize_l2(lambda: number): void {
    // W := W * (1 - lambda)
    for (let i = 0; i < this.W.length; i++) {
      this.W[i] *= 1 - lambda;
    }
  }

  /**
   * L1 м •к·ңнҷ” (LASSO)
   */
  regularize_l1(lambda: number): void {
    for (let i = 0; i < this.W.length; i++) {
      const sign = this.W[i] > 0 ? 1 : -1;
      this.W[i] -= sign * lambda;
    }
  }

  /**
   * кё°мҡёкё° нҒҙлҰ¬н•‘ (gradient clipping)
   */
  clip_gradient(dW: Matrix, db: Tensor, max_norm: number): void {
    let norm_W = TensorOps.l2_norm(dW);
    if (norm_W > max_norm) {
      const scale = max_norm / norm_W;
      for (let i = 0; i < dW.length; i++) {
        dW[i] *= scale;
      }
    }

    let norm_b = TensorOps.l2_norm(db);
    if (norm_b > max_norm) {
      const scale = max_norm / norm_b;
      for (let i = 0; i < db.length; i++) {
        db[i] *= scale;
      }
    }
  }

  /**
   * нҳ„мһ¬ к°ҖмӨ‘м№ҳ л…ёлҰ„
   */
  weight_norm(): number {
    const norm_W = TensorOps.l2_norm(this.W);
    const norm_b = TensorOps.l2_norm(this.b);
    return Math.sqrt(norm_W * norm_W + norm_b * norm_b);
  }

  /**
   * мқёмҪ”лҚ” мғҒнғң м ҖмһҘ
   */
  serialize(): {
    W: number[];
    b: number[];
    input_dim: number;
    output_dim: number;
  } {
    return {
      W: Array.from(this.W),
      b: Array.from(this.b),
      input_dim: this.input_dim,
      output_dim: this.output_dim,
    };
  }

  /**
   * мқёмҪ”лҚ” мғҒнғң ліөмӣҗ
   */
  static deserialize(data: {
    W: number[];
    b: number[];
    input_dim: number;
    output_dim: number;
  }): QueryEncoder {
    const encoder = new QueryEncoder(data.input_dim, data.output_dim);
    encoder.W = new Float64Array(data.W);
    encoder.b = new Float64Array(data.b);
    return encoder;
  }

  /**
   * л””лІ„к№…мҡ© мғҒнғң м¶ңл Ҙ
   */
  debug_info(): string {
    const w_norm = TensorOps.l2_norm(this.W);
    const b_norm = TensorOps.l2_norm(this.b);
    return (
      `QueryEncoder(${this.input_dim}вҶ’${this.output_dim}): ` +
      `||W||=${w_norm.toFixed(4)}, ||b||=${b_norm.toFixed(4)}`
    );
  }
}

/**
 * лӢӨмёө мқёмҪ”лҚ”
 * м—¬лҹ¬ мёөмқҳ м„ нҳ• ліҖнҷҳмқ„ мқҙмҡ©н•ң к№ҠмқҖ мқёмҪ”л”©
 */
export class DeepQueryEncoder {
  layers: QueryEncoder[];
  num_layers: number;

  constructor(dimensions: number[]) {
    if (dimensions.length < 2) {
      throw new Error("Need at least input and output dimensions");
    }

    this.num_layers = dimensions.length - 1;
    this.layers = [];

    for (let i = 0; i < this.num_layers; i++) {
      const input_dim = dimensions[i];
      const output_dim = dimensions[i + 1];
      this.layers.push(new QueryEncoder(input_dim, output_dim));
    }
  }

  /**
   * мҲңм „нҢҢ
   */
  forward(q: Tensor): Tensor {
    let x = q;
    for (let i = 0; i < this.num_layers; i++) {
      x = this.layers[i].encode(x);
      // л§Ҳм§Җл§ү мёө м ңмҷё ReLU м Ғмҡ©
      if (i < this.num_layers - 1) {
        x = TensorOps.relu(x);
      }
    }
    return x;
  }

  /**
   * м—ӯм „нҢҢ
   */
  backward(grad_output: Tensor): Tensor {
    let grad = grad_output;
    for (let i = this.num_layers - 1; i >= 0; i--) {
      const { dW, db, dq } = this.layers[i].gradient(grad, grad); // к°„лӢЁнһҲ
      grad = dq;

      // л§Ҳм§Җл§ү мёө м ңмҷё ReLU к·ёлһҳл””м–ёнҠё
      if (i > 0) {
        // grad = TensorOps.grad_relu(grad, ...); // мқҙм „ нҷңм„ұнҷ” к°’ н•„мҡ”
      }
    }
    return grad;
  }

  /**
   * л””лІ„к№…мҡ© м •ліҙ
   */
  debug_info(): string {
    return this.layers.map((l) => l.debug_info()).join("\n");
  }
}

/**
 * PostMindLang Runtime: Parallel Path Execution
 * 3к°ң кІҪлЎң (л¶„м„қм Ғ, м°Ҫмқҳм Ғ, кІҪн—ҳм Ғ) мӢӨн–ү
 * к°Ғ кІҪлЎң: м„ нҳ• мӮ¬мҳҒ (linear projection)
 */

import { Tensor, Matrix, TensorOps } from "./tensor";

/**
 * кІҪлЎң мӢӨн–ү лӘЁл“Ҳ
 * 3к°ңмқҳ лҸ…лҰҪм Ғмқё м„ нҳ• мӮ¬мҳҒ:
 * - P_a: analytical path (л¶„м„қм Ғ мӮ¬кі )
 * - P_b: creative path (м°Ҫмқҳм Ғ мӮ¬кі )
 * - P_c: empirical path (кІҪн—ҳм Ғ мӮ¬кі )
 */
export class PathExecutor {
  /**
   * л¶„м„қм Ғ кІҪлЎң: в„қ^512 вҶ’ в„қ^256
   */
  P_a: Matrix;

  /**
   * м°Ҫмқҳм Ғ кІҪлЎң: в„қ^512 вҶ’ в„қ^256
   */
  P_b: Matrix;

  /**
   * кІҪн—ҳм Ғ кІҪлЎң: в„қ^512 вҶ’ в„қ^256
   */
  P_c: Matrix;

  /**
   * мһ…л Ҙ/м¶ңл Ҙ м°Ёмӣҗ
   */
  input_dim: number;
  output_dim: number;

  /**
   * кІҪлЎңлі„ нҺён–Ҙ (м„ нғқмӮ¬н•ӯ)
   */
  b_a: Tensor;
  b_b: Tensor;
  b_c: Tensor;

  constructor(input_dim: number = 512, output_dim: number = 256) {
    this.input_dim = input_dim;
    this.output_dim = output_dim;

    // Xavier мҙҲкё°нҷ”: W ~ N(0, sqrt(2/(n_in + n_out)))
    const scale = Math.sqrt(
      2.0 / (input_dim + output_dim)
    );

    // к°Ғ кІҪлЎңлі„ мӮ¬мҳҒ н–үл ¬ мҙҲкё°нҷ”
    this.P_a = TensorOps.randn(input_dim * output_dim);
    for (let i = 0; i < this.P_a.length; i++) {
      this.P_a[i] *= scale;
    }

    this.P_b = TensorOps.randn(input_dim * output_dim);
    for (let i = 0; i < this.P_b.length; i++) {
      this.P_b[i] *= scale;
    }

    this.P_c = TensorOps.randn(input_dim * output_dim);
    for (let i = 0; i < this.P_c.length; i++) {
      this.P_c[i] *= scale;
    }

    // нҺён–Ҙ мҙҲкё°нҷ”
    this.b_a = TensorOps.zeros(output_dim);
    this.b_b = TensorOps.zeros(output_dim);
    this.b_c = TensorOps.zeros(output_dim);
  }

  /**
   * 3к°ң кІҪлЎң лі‘л ¬ мӢӨн–ү
   * z вҲҲ в„қ^512 вҶ’ z_a, z_b, z_c вҲҲ в„қ^256
   */
  execute_parallel(z: Tensor): {
    z_a: Tensor;
    z_b: Tensor;
    z_c: Tensor;
  } {
    if (z.length !== this.input_dim) {
      throw new Error(
        `Input dimension mismatch: ${z.length} vs ${this.input_dim}`
      );
    }

    // 3к°ң кІҪлЎң лҸҷмӢң кі„мӮ° (лі‘л ¬нҷ” к°ҖлҠҘ)
    const z_a = TensorOps.add(
      TensorOps.matvec(this.P_a, z, this.output_dim, this.input_dim),
      this.b_a
    );
    const z_b = TensorOps.add(
      TensorOps.matvec(this.P_b, z, this.output_dim, this.input_dim),
      this.b_b
    );
    const z_c = TensorOps.add(
      TensorOps.matvec(this.P_c, z, this.output_dim, this.input_dim),
      this.b_c
    );

    return { z_a, z_b, z_c };
  }

  /**
   * л°°м№ҳ лі‘л ¬ мӢӨн–ү
   */
  execute_batch(
    Z: Matrix,
    batch_size: number
  ): {
    Z_a: Matrix;
    Z_b: Matrix;
    Z_c: Matrix;
  } {
    // Z вҲҲ в„қ^(batch_size Г— 512)
    const Z_a = TensorOps.matmul_batch(
      Z,
      this.P_a,
      batch_size,
      this.input_dim,
      this.output_dim
    );
    const Z_b = TensorOps.matmul_batch(
      Z,
      this.P_b,
      batch_size,
      this.input_dim,
      this.output_dim
    );
    const Z_c = TensorOps.matmul_batch(
      Z,
      this.P_c,
      batch_size,
      this.input_dim,
      this.output_dim
    );

    // нҺён–Ҙ лёҢлЎңл“ңмәҗмҠӨнҢ…
    for (let b = 0; b < batch_size; b++) {
      for (let j = 0; j < this.output_dim; j++) {
        Z_a[b * this.output_dim + j] += this.b_a[j];
        Z_b[b * this.output_dim + j] += this.b_b[j];
        Z_c[b * this.output_dim + j] += this.b_c[j];
      }
    }

    return { Z_a, Z_b, Z_c };
  }

  /**
   * кІҪлЎң A к·ёлһҳл””м–ёнҠё
   */
  gradient_a(grad_z_a: Tensor, z: Tensor): {
    dP_a: Matrix;
    db_a: Tensor;
    dz_upstream: Tensor;
  } {
    // вҲӮL/вҲӮz_a = grad_z_a (мқҙлҜё л°ӣмқҢ)
    // вҲӮL/вҲӮP_a = grad_z_a вҠ— z
    const dP_a = TensorOps.outer(z, grad_z_a);

    // вҲӮL/вҲӮb_a = grad_z_a
    const db_a = TensorOps.copy(grad_z_a);

    // вҲӮL/вҲӮz = P_a^T @ grad_z_a (м—ӯм „нҢҢ)
    const P_a_T = TensorOps.transpose(
      this.P_a,
      this.input_dim,
      this.output_dim
    );
    const dz_upstream = TensorOps.matvec(
      P_a_T,
      grad_z_a,
      this.input_dim,
      this.output_dim
    );

    return { dP_a, db_a, dz_upstream };
  }

  /**
   * кІҪлЎң B к·ёлһҳл””м–ёнҠё
   */
  gradient_b(grad_z_b: Tensor, z: Tensor): {
    dP_b: Matrix;
    db_b: Tensor;
    dz_upstream: Tensor;
  } {
    const dP_b = TensorOps.outer(z, grad_z_b);
    const db_b = TensorOps.copy(grad_z_b);

    const P_b_T = TensorOps.transpose(
      this.P_b,
      this.input_dim,
      this.output_dim
    );
    const dz_upstream = TensorOps.matvec(
      P_b_T,
      grad_z_b,
      this.input_dim,
      this.output_dim
    );

    return { dP_b, db_b, dz_upstream };
  }

  /**
   * кІҪлЎң C к·ёлһҳл””м–ёнҠё
   */
  gradient_c(grad_z_c: Tensor, z: Tensor): {
    dP_c: Matrix;
    db_c: Tensor;
    dz_upstream: Tensor;
  } {
    const dP_c = TensorOps.outer(z, grad_z_c);
    const db_c = TensorOps.copy(grad_z_c);

    const P_c_T = TensorOps.transpose(
      this.P_c,
      this.input_dim,
      this.output_dim
    );
    const dz_upstream = TensorOps.matvec(
      P_c_T,
      grad_z_c,
      this.input_dim,
      this.output_dim
    );

    return { dP_c, db_c, dz_upstream };
  }

  /**
   * м „мІҙ к·ёлһҳл””м–ёнҠё (лӘЁл“  кІҪлЎң)
   */
  gradient_all(
    grad_z_a: Tensor,
    grad_z_b: Tensor,
    grad_z_c: Tensor,
    z: Tensor
  ): {
    dP_a: Matrix;
    db_a: Tensor;
    dP_b: Matrix;
    db_b: Tensor;
    dP_c: Matrix;
    db_c: Tensor;
    dz: Tensor;
  } {
    const grad_a = this.gradient_a(grad_z_a, z);
    const grad_b = this.gradient_b(grad_z_b, z);
    const grad_c = this.gradient_c(grad_z_c, z);

    // м—ӯм „нҢҢ к·ёлһҳл””м–ёнҠё н•©мӮ°
    const dz = TensorOps.add(
      grad_a.dz_upstream,
      TensorOps.add(grad_b.dz_upstream, grad_c.dz_upstream)
    );

    return {
      dP_a: grad_a.dP_a,
      db_a: grad_a.db_a,
      dP_b: grad_b.dP_b,
      db_b: grad_b.db_b,
      dP_c: grad_c.dP_c,
      db_c: grad_c.db_c,
      dz,
    };
  }

  /**
   * л°°м№ҳ к·ёлһҳл””м–ёнҠё
   */
  gradient_batch(
    grad_Z_a: Matrix,
    grad_Z_b: Matrix,
    grad_Z_c: Matrix,
    Z: Matrix,
    batch_size: number
  ): {
    dP_a: Matrix;
    db_a: Tensor;
    dP_b: Matrix;
    db_b: Tensor;
    dP_c: Matrix;
    db_c: Tensor;
    dZ: Matrix;
  } {
    // к°Ғ кІҪлЎңмқҳ к·ёлһҳл””м–ёнҠё кі„мӮ° (л°°м№ҳ)
    const dP_a = TensorOps.zeros(this.input_dim * this.output_dim);
    const db_a = TensorOps.zeros(this.output_dim);
    let dZ_a = TensorOps.zeros(batch_size * this.input_dim);

    for (let b = 0; b < batch_size; b++) {
      const z_b_start = b * this.input_dim;
      const grad_z_a_b_start = b * this.output_dim;
      const grad_z_a_b = grad_Z_a.slice(
        grad_z_a_b_start,
        grad_z_a_b_start + this.output_dim
      );
      const z_b = Z.slice(z_b_start, z_b_start + this.input_dim);

      // dP_a += z_b вҠ— grad_z_a_b
      const outer_prod = TensorOps.outer(z_b, grad_z_a_b);
      for (let i = 0; i < dP_a.length; i++) {
        dP_a[i] += outer_prod[i];
      }

      // db_a += grad_z_a_b
      for (let i = 0; i < this.output_dim; i++) {
        db_a[i] += grad_z_a_b[i];
      }

      // dz_a_b = P_a^T @ grad_z_a_b
      const P_a_T = TensorOps.transpose(
        this.P_a,
        this.input_dim,
        this.output_dim
      );
      const dz_a_b = TensorOps.matvec(
        P_a_T,
        grad_z_a_b,
        this.input_dim,
        this.output_dim
      );
      for (let i = 0; i < this.input_dim; i++) {
        dZ_a[z_b_start + i] = dz_a_b[i];
      }
    }

    // кІҪлЎң B, CлҸ„ лҸҷмқј
    const dP_b = TensorOps.zeros(this.input_dim * this.output_dim);
    const db_b = TensorOps.zeros(this.output_dim);
    let dZ_b = TensorOps.zeros(batch_size * this.input_dim);

    for (let b = 0; b < batch_size; b++) {
      const z_b_start = b * this.input_dim;
      const grad_z_b_b_start = b * this.output_dim;
      const grad_z_b_b = grad_Z_b.slice(
        grad_z_b_b_start,
        grad_z_b_b_start + this.output_dim
      );
      const z_b = Z.slice(z_b_start, z_b_start + this.input_dim);

      const outer_prod = TensorOps.outer(z_b, grad_z_b_b);
      for (let i = 0; i < dP_b.length; i++) {
        dP_b[i] += outer_prod[i];
      }

      for (let i = 0; i < this.output_dim; i++) {
        db_b[i] += grad_z_b_b[i];
      }

      const P_b_T = TensorOps.transpose(
        this.P_b,
        this.input_dim,
        this.output_dim
      );
      const dz_b_b = TensorOps.matvec(
        P_b_T,
        grad_z_b_b,
        this.input_dim,
        this.output_dim
      );
      for (let i = 0; i < this.input_dim; i++) {
        dZ_b[z_b_start + i] = dz_b_b[i];
      }
    }

    const dP_c = TensorOps.zeros(this.input_dim * this.output_dim);
    const db_c = TensorOps.zeros(this.output_dim);
    let dZ_c = TensorOps.zeros(batch_size * this.input_dim);

    for (let b = 0; b < batch_size; b++) {
      const z_b_start = b * this.input_dim;
      const grad_z_c_b_start = b * this.output_dim;
      const grad_z_c_b = grad_Z_c.slice(
        grad_z_c_b_start,
        grad_z_c_b_start + this.output_dim
      );
      const z_b = Z.slice(z_b_start, z_b_start + this.input_dim);

      const outer_prod = TensorOps.outer(z_b, grad_z_c_b);
      for (let i = 0; i < dP_c.length; i++) {
        dP_c[i] += outer_prod[i];
      }

      for (let i = 0; i < this.output_dim; i++) {
        db_c[i] += grad_z_c_b[i];
      }

      const P_c_T = TensorOps.transpose(
        this.P_c,
        this.input_dim,
        this.output_dim
      );
      const dz_c_b = TensorOps.matvec(
        P_c_T,
        grad_z_c_b,
        this.input_dim,
        this.output_dim
      );
      for (let i = 0; i < this.input_dim; i++) {
        dZ_c[z_b_start + i] = dz_c_b[i];
      }
    }

    // м „мІҙ м—ӯм „нҢҢ к·ёлһҳл””м–ёнҠё
    const dZ = TensorOps.add(dZ_a, TensorOps.add(dZ_b, dZ_c));

    return { dP_a, db_a, dP_b, db_b, dP_c, db_c, dZ };
  }

  /**
   * к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё (SGD)
   */
  update(
    dP_a: Matrix,
    db_a: Tensor,
    dP_b: Matrix,
    db_b: Tensor,
    dP_c: Matrix,
    db_c: Tensor,
    learning_rate: number
  ): void {
    // кІҪлЎң A
    for (let i = 0; i < this.P_a.length; i++) {
      this.P_a[i] -= learning_rate * dP_a[i];
    }
    for (let i = 0; i < this.b_a.length; i++) {
      this.b_a[i] -= learning_rate * db_a[i];
    }

    // кІҪлЎң B
    for (let i = 0; i < this.P_b.length; i++) {
      this.P_b[i] -= learning_rate * dP_b[i];
    }
    for (let i = 0; i < this.b_b.length; i++) {
      this.b_b[i] -= learning_rate * db_b[i];
    }

    // кІҪлЎң C
    for (let i = 0; i < this.P_c.length; i++) {
      this.P_c[i] -= learning_rate * dP_c[i];
    }
    for (let i = 0; i < this.b_c.length; i++) {
      this.b_c[i] -= learning_rate * db_c[i];
    }
  }

  /**
   * кІҪлЎңлі„ нҷңм„ұнҷ” нҶөкі„
   */
  path_stats(z_a: Tensor, z_b: Tensor, z_c: Tensor): {
    mean_a: number;
    std_a: number;
    mean_b: number;
    std_b: number;
    mean_c: number;
    std_c: number;
  } {
    return {
      mean_a: TensorOps.mean(z_a),
      std_a: TensorOps.std(z_a),
      mean_b: TensorOps.mean(z_b),
      std_b: TensorOps.std(z_b),
      mean_c: TensorOps.mean(z_c),
      std_c: TensorOps.std(z_c),
    };
  }

  /**
   * кІҪлЎң л¶„мӮ°лҸ„ (path divergence)
   * 3к°ң кІҪлЎңк°Җ м–јл§ҲлӮҳ лӢӨлҘём§Җ мёЎм •
   */
  path_divergence(z_a: Tensor, z_b: Tensor, z_c: Tensor): number {
    const dist_ab = TensorOps.l2_norm(TensorOps.subtract(z_a, z_b));
    const dist_bc = TensorOps.l2_norm(TensorOps.subtract(z_b, z_c));
    const dist_ca = TensorOps.l2_norm(TensorOps.subtract(z_c, z_a));
    return (dist_ab + dist_bc + dist_ca) / 3.0;
  }

  /**
   * м§Ғл ¬нҷ”
   */
  serialize(): {
    P_a: number[];
    P_b: number[];
    P_c: number[];
    b_a: number[];
    b_b: number[];
    b_c: number[];
    input_dim: number;
    output_dim: number;
  } {
    return {
      P_a: Array.from(this.P_a),
      P_b: Array.from(this.P_b),
      P_c: Array.from(this.P_c),
      b_a: Array.from(this.b_a),
      b_b: Array.from(this.b_b),
      b_c: Array.from(this.b_c),
      input_dim: this.input_dim,
      output_dim: this.output_dim,
    };
  }

  /**
   * м—ӯм§Ғл ¬нҷ”
   */
  static deserialize(data: {
    P_a: number[];
    P_b: number[];
    P_c: number[];
    b_a: number[];
    b_b: number[];
    b_c: number[];
    input_dim: number;
    output_dim: number;
  }): PathExecutor {
    const executor = new PathExecutor(data.input_dim, data.output_dim);
    executor.P_a = new Float64Array(data.P_a);
    executor.P_b = new Float64Array(data.P_b);
    executor.P_c = new Float64Array(data.P_c);
    executor.b_a = new Float64Array(data.b_a);
    executor.b_b = new Float64Array(data.b_b);
    executor.b_c = new Float64Array(data.b_c);
    return executor;
  }

  /**
   * л””лІ„к№… м •ліҙ
   */
  debug_info(): string {
    const norm_a = TensorOps.l2_norm(this.P_a);
    const norm_b = TensorOps.l2_norm(this.P_b);
    const norm_c = TensorOps.l2_norm(this.P_c);
    return (
      `PathExecutor(${this.input_dim}вҶ’${this.output_dim}): ` +
      `||P_a||=${norm_a.toFixed(4)}, ||P_b||=${norm_b.toFixed(4)}, ` +
      `||P_c||=${norm_c.toFixed(4)}`
    );
  }
}

/**
 * PostMindLang Runtime: Ensemble Module
 * 3к°ң кІҪлЎңмқҳ м•ҷмғҒлё” (к°ҖмӨ‘ н•©)
 * к°ҖмӨ‘м№ҳлҠ” мҝјлҰ¬ кё°л°ҳмңјлЎң лҸҷм ҒмңјлЎң кІ°м •лҗЁ
 */

import { Tensor, Matrix, TensorOps } from "./tensor";
import { QueryEncoder } from "./encoding";

/**
 * м•ҷмғҒлё” лӘЁл“Ҳ
 * к°ҖмӨ‘ н•©: e = w_a * z_a + w_b * z_b + w_c * z_c
 * к°ҖмӨ‘м№ҳ: w = softmax(W_weight @ q)
 */
export class EnsembleModule {
  /**
   * к°ҖмӨ‘м№ҳ н•ЁмҲҳлҘј мң„н•ң мқёмҪ”лҚ”
   * f_weight: в„қ^768 вҶ’ в„қ^3
   */
  weight_encoder: QueryEncoder;

  /**
   * мҳЁлҸ„ нҢҢлқјлҜён„° (softmax temperature)
   */
  tau: number;

  constructor(query_dim: number = 768, temperature: number = 0.8) {
    // к°„лӢЁн•ң кө¬нҳ„: 1мёө мқёмҪ”лҚ” (768 вҶ’ 3)
    this.weight_encoder = new QueryEncoder(query_dim, 3);
    this.tau = temperature;
  }

  /**
   * к°ҖмӨ‘м№ҳ кі„мӮ°: w = softmax(W_weight @ q / П„)
   * кІ°кіј: w вҲҲ О”^2 (simplex - нҷ•лҘ  л¶„нҸ¬)
   */
  compute_weights(q: Tensor): Tensor {
    // f_weight(q) вҲҲ в„қ^3
    const logits = this.weight_encoder.encode(q);

    // softmax(logits / П„)
    const weights = TensorOps.softmax(logits, this.tau);

    return weights;
  }

  /**
   * л°°м№ҳ к°ҖмӨ‘м№ҳ кі„мӮ°
   */
  compute_weights_batch(Q: Matrix, batch_size: number): Matrix {
    const logits = this.weight_encoder.encode_batch(Q, batch_size);
    const weights = TensorOps.softmax(logits, this.tau);
    return weights;
  }

  /**
   * м•ҷмғҒлё” кІ°н•©
   * e = w[0] * z_a + w[1] * z_b + w[2] * z_c
   */
  combine(
    w: Tensor,
    z_a: Tensor,
    z_b: Tensor,
    z_c: Tensor
  ): Tensor {
    if (w.length !== 3) {
      throw new Error(`Weights dimension must be 3, got ${w.length}`);
    }

    // к°Ғ кІҪлЎңлҘј к°ҖмӨ‘м№ҳлЎң мҠӨмјҖмқј
    const scaled_a = TensorOps.scale(z_a, w[0]);
    const scaled_b = TensorOps.scale(z_b, w[1]);
    const scaled_c = TensorOps.scale(z_c, w[2]);

    // н•©мӮ°
    const e = TensorOps.add(scaled_a, TensorOps.add(scaled_b, scaled_c));

    return e;
  }

  /**
   * л°°м№ҳ м•ҷмғҒлё” кІ°н•©
   */
  combine_batch(
    W: Matrix,
    Z_a: Matrix,
    Z_b: Matrix,
    Z_c: Matrix,
    batch_size: number,
    path_dim: number
  ): Matrix {
    const E = TensorOps.zeros(batch_size * path_dim);

    for (let b = 0; b < batch_size; b++) {
      const w_start = b * 3;
      const z_start = b * path_dim;

      const w_a = W[w_start];
      const w_b = W[w_start + 1];
      const w_c = W[w_start + 2];

      for (let j = 0; j < path_dim; j++) {
        E[z_start + j] =
          w_a * Z_a[z_start + j] +
          w_b * Z_b[z_start + j] +
          w_c * Z_c[z_start + j];
      }
    }

    return E;
  }

  /**
   * м•ҷмғҒлё” к·ёлһҳл””м–ёнҠё
   * вҲӮL/вҲӮw, вҲӮL/вҲӮz_a, вҲӮL/вҲӮz_b, вҲӮL/вҲӮz_c кі„мӮ°
   */
  gradient(
    grad_e: Tensor,
    w: Tensor,
    z_a: Tensor,
    z_b: Tensor,
    z_c: Tensor
  ): {
    grad_w: Tensor;
    grad_z_a: Tensor;
    grad_z_b: Tensor;
    grad_z_c: Tensor;
  } {
    // вҲӮL/вҲӮz_a = w[0] * grad_e
    const grad_z_a = TensorOps.scale(grad_e, w[0]);

    // вҲӮL/вҲӮz_b = w[1] * grad_e
    const grad_z_b = TensorOps.scale(grad_e, w[1]);

    // вҲӮL/вҲӮz_c = w[2] * grad_e
    const grad_z_c = TensorOps.scale(grad_e, w[2]);

    // вҲӮL/вҲӮw = [dot(grad_e, z_a), dot(grad_e, z_b), dot(grad_e, z_c)]
    const grad_w_pre = new Float64Array(3);
    grad_w_pre[0] = TensorOps.dot(grad_e, z_a);
    grad_w_pre[1] = TensorOps.dot(grad_e, z_b);
    grad_w_pre[2] = TensorOps.dot(grad_e, z_c);

    // softmax м—ӯм „нҢҢ
    // вҲӮL/вҲӮlogits = вҲӮL/вҲӮw вҠҷ (w - wВ·w^T)
    // лӢЁмҲңнҷ”: softmax к·ёлһҳл””м–ёнҠё м Ғмҡ©
    const grad_w = TensorOps.grad_softmax(grad_w_pre, w);

    return { grad_w, grad_z_a, grad_z_b, grad_z_c };
  }

  /**
   * к°ҖмӨ‘м№ҳ н•ЁмҲҳмқҳ к·ёлһҳл””м–ёнҠё
   */
  gradient_weight_fn(grad_w: Tensor, q: Tensor): {
    dW_weight: Matrix;
    db_weight: Tensor;
    dq: Tensor;
  } {
    return this.weight_encoder.gradient(grad_w, q);
  }

  /**
   * л°°м№ҳ к°ҖмӨ‘м№ҳ н•ЁмҲҳ к·ёлһҳл””м–ёнҠё
   */
  gradient_weight_fn_batch(
    grad_W: Matrix,
    Q: Matrix,
    batch_size: number
  ): {
    dW_weight: Matrix;
    db_weight: Tensor;
    dQ: Matrix;
  } {
    return this.weight_encoder.gradient_batch(grad_W, Q, batch_size);
  }

  /**
   * к°ҖмӨ‘м№ҳ к· нҳ•лҸ„ (weight balance)
   * к°’мқҙ нҒҙмҲҳлЎқ к°ҖмӨ‘м№ҳк°Җ к· л“ұн•ҳкІҢ л¶„нҸ¬
   */
  weight_balance(w: Tensor): number {
    // м—”нҠёлЎңн”ј: -ОЈ w_i * log(w_i)
    // мөңлҢҖк°’: log(3) вүҲ 1.099
    let entropy = 0;
    for (let i = 0; i < 3; i++) {
      if (w[i] > 1e-10) {
        entropy -= w[i] * Math.log(w[i]);
      }
    }
    return entropy / Math.log(3);
  }

  /**
   * мҡ°м„ё кІҪлЎң м„ нғқ
   * к°ҖмһҘ лҶ’мқҖ к°ҖмӨ‘м№ҳлҘј к°Җм§„ кІҪлЎң
   */
  dominant_path(w: Tensor): { path: "a" | "b" | "c"; weight: number } {
    let max_weight = w[0];
    let max_idx = 0;

    for (let i = 1; i < 3; i++) {
      if (w[i] > max_weight) {
        max_weight = w[i];
        max_idx = i;
      }
    }

    const path_names: ("a" | "b" | "c")[] = ["a", "b", "c"];
    return { path: path_names[max_idx], weight: max_weight };
  }

  /**
   * к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё
   */
  update(dW: Matrix, db: Tensor, learning_rate: number): void {
    this.weight_encoder.update(dW, db, learning_rate);
  }

  /**
   * мҳЁлҸ„ мҠӨмјҖмӨ„л§Ғ (temperature scheduling)
   * нӣҲл Ё м§„н–үм—җ л”°лқј мҳЁлҸ„ к°җмҶҢ
   */
  set_temperature(t: number, total_steps: number, current_step: number): void {
    // м„ нҳ• к°җмҶҢ
    this.tau = t * (1 - current_step / total_steps);
  }

  /**
   * к°ҖмӨ‘м№ҳ м •к·ңнҷ” (weight regularization)
   * к°ҖмӨ‘м№ҳ к°„ м°ЁмқҙлҘј мөңмҶҢнҷ”н•ҳм—¬ кІҪлЎң к· нҳ• мң м§Җ
   */
  regularize_balance(weight_lambda: number): Tensor {
    // вҲӮL_reg/вҲӮw = О» * (w - 1/3)
    // лӘЁл“  к°ҖмӨ‘м№ҳлҘј 1/3мңјлЎң мң лҸ„н•ҳлҠ” м •к·ңнҷ”
    const reg = new Float64Array(3);
    for (let i = 0; i < 3; i++) {
      reg[i] = weight_lambda * (-1.0 / 3.0); // лӘ©н‘ң: 1/3
    }
    return reg;
  }

  /**
   * кІҪлЎң нҳјн•©лҸ„ (path mixing)
   * лӢЁмқј кІҪлЎңм—җ мқҳмЎҙн•ҳлҠ” м •лҸ„ мёЎм • (0: к· л“ұ, 1: мҷ„м „нһҲ н•ң кІҪлЎң)
   */
  path_concentration(w: Tensor): number {
    // Herfindahl index: ОЈ w_i^2
    // лІ”мң„: [1/3, 1]
    let concentration = 0;
    for (let i = 0; i < 3; i++) {
      concentration += w[i] * w[i];
    }
    return (concentration - 1.0 / 3.0) / (1.0 - 1.0 / 3.0);
  }

  /**
   * м§Ғл ¬нҷ”
   */
  serialize(): {
    weight_encoder: ReturnType<typeof QueryEncoder.prototype.serialize>;
    tau: number;
  } {
    return {
      weight_encoder: this.weight_encoder.serialize(),
      tau: this.tau,
    };
  }

  /**
   * м—ӯм§Ғл ¬нҷ”
   */
  static deserialize(data: {
    weight_encoder: ReturnType<typeof QueryEncoder.prototype.serialize>;
    tau: number;
  }): EnsembleModule {
    const module = new EnsembleModule();
    module.weight_encoder = QueryEncoder.deserialize(data.weight_encoder);
    module.tau = data.tau;
    return module;
  }

  /**
   * л””лІ„к№… м •ліҙ
   */
  debug_info(): string {
    return (
      `EnsembleModule (П„=${this.tau.toFixed(3)}): ` +
      `${this.weight_encoder.debug_info()}`
    );
  }
}

/**
 * кі кёү м•ҷмғҒлё”: лҸҷм Ғ к°ҖмӨ‘м№ҳ мЎ°м •
 */
export class AdaptiveEnsembleModule extends EnsembleModule {
  /**
   * мӢ лў°лҸ„ кё°л°ҳ к°ҖмӨ‘м№ҳ мЎ°м •
   * confidence к°’мқҙ лҶ’мқ„мҲҳлЎқ нҳ„мһ¬ к°ҖмӨ‘м№ҳлҘј мң м§Җ
   */
  adjust_weights_by_confidence(
    w: Tensor,
    confidence: number
  ): Tensor {
    // w' = confidence * w + (1 - confidence) * uniform
    const uniform = new Float64Array(3);
    uniform.fill(1.0 / 3.0);

    const w_adjusted = new Float64Array(3);
    for (let i = 0; i < 3; i++) {
      w_adjusted[i] = confidence * w[i] + (1 - confidence) * uniform[i];
    }

    return TensorOps.softmax(w_adjusted);
  }

  /**
   * к·ёлһҳл””м–ёнҠё нҒ¬кё°м—җ л”°лҘё к°ҖмӨ‘м№ҳ мЎ°м •
   */
  adjust_weights_by_gradient(
    w: Tensor,
    grad_z_a: Tensor,
    grad_z_b: Tensor,
    grad_z_c: Tensor
  ): Tensor {
    // к·ёлһҳл””м–ёнҠё нҒ¬кё° кі„мӮ°
    const mag_a = TensorOps.l2_norm(grad_z_a);
    const mag_b = TensorOps.l2_norm(grad_z_b);
    const mag_c = TensorOps.l2_norm(grad_z_c);

    // нҒ¬кё°м—җ л°ҳл№„лЎҖн•ҳлҠ” к°ҖмӨ‘м№ҳ (н•ҷмҠө мҶҚлҸ„ к· нҳ•)
    const inv_mag = new Float64Array(3);
    const total_inv = 1 / mag_a + 1 / mag_b + 1 / mag_c;
    inv_mag[0] = (1 / mag_a) / total_inv;
    inv_mag[1] = (1 / mag_b) / total_inv;
    inv_mag[2] = (1 / mag_c) / total_inv;

    // нҳ„мһ¬ к°ҖмӨ‘м№ҳмҷҖ нҳјн•©
    const blend_factor = 0.9; // нҳ„мһ¬ к°ҖмӨ‘м№ҳ мң м§Җ м •лҸ„
    const w_blended = new Float64Array(3);
    for (let i = 0; i < 3; i++) {
      w_blended[i] = blend_factor * w[i] + (1 - blend_factor) * inv_mag[i];
    }

    return TensorOps.softmax(w_blended);
  }
}

/**
 * PostMindLang Runtime: Critique Module
 * мһҗк°Җ л№„нҢҗ (вҲҮL кі„мӮ°)
 * мҶҗмӢӨ н•ЁмҲҳмқҳ к·ёлһҳл””м–ёнҠёлҘј нҶөн•ң мӢ лў°лҸ„ мёЎм •
 */

import { Tensor, TensorOps } from "./tensor";

/**
 * мҶҗмӢӨ н•ЁмҲҳ нғҖмһ…
 */
export type LossFn = (ensemble: Tensor, query: Tensor) => number;

/**
 * к·ёлһҳл””м–ёнҠё н•ЁмҲҳ нғҖмһ…
 */
export type GradientFn = (ensemble: Tensor, query: Tensor) => Tensor;

/**
 * л№„нҢҗ лӘЁл“Ҳ
 * м¶ңл Ҙ н’Ҳм§Ҳмқ„ нҸүк°Җн•ҳкі  к°ңм„  м—¬л¶ҖлҘј кІ°м •
 */
export class CritiqueModule {
  /**
   * мҶҗмӢӨ н•ЁмҲҳ
   */
  loss_fn: LossFn;

  /**
   * мҶҗмӢӨ н•ЁмҲҳмқҳ к·ёлһҳл””м–ёнҠё
   */
  grad_fn: GradientFn;

  /**
   * мӢ лў°лҸ„ мһ„кі„к°’
   */
  confidence_threshold: number;

  /**
   * к·ёлһҳл””м–ёнҠё м •к·ңнҷ” мқёмҲҳ
   */
  grad_normalization: number;

  constructor(
    loss_fn: LossFn,
    grad_fn: GradientFn,
    confidence_threshold: number = 0.8,
    grad_normalization: number = 10.0
  ) {
    this.loss_fn = loss_fn;
    this.grad_fn = grad_fn;
    this.confidence_threshold = confidence_threshold;
    this.grad_normalization = grad_normalization;
  }

  /**
   * л№„нҢҗ мҲҳн–ү: вҲҮL кі„мӮ° л°Ҹ мӢ лў°лҸ„ мёЎм •
   */
  critique(ensemble: Tensor, query: Tensor): {
    grad: Tensor;
    confidence: number;
    loss: number;
  } {
    // мҶҗмӢӨк°’ кі„мӮ°
    const loss = this.loss_fn(ensemble, query);

    // к·ёлһҳл””м–ёнҠё кі„мӮ°: Оҙ = вҲҮ_ensemble L
    const grad = this.grad_fn(ensemble, query);

    // мӢ лў°лҸ„ кі„мӮ°
    // confidence = max(0, 1 - ||grad||_2 / normalization_factor)
    const grad_norm = TensorOps.l2_norm(grad);
    const confidence = Math.max(
      0,
      1 - grad_norm / this.grad_normalization
    );

    return { grad, confidence, loss };
  }

  /**
   * л°°м№ҳ л№„нҢҗ
   */
  critique_batch(
    ensembles: Float64Array,
    queries: Float64Array,
    batch_size: number,
    ensemble_dim: number,
    query_dim: number
  ): {
    grads: Float64Array;
    confidences: number[];
    losses: number[];
  } {
    const grads = new Float64Array(batch_size * ensemble_dim);
    const confidences: number[] = [];
    const losses: number[] = [];

    for (let b = 0; b < batch_size; b++) {
      const e_start = b * ensemble_dim;
      const q_start = b * query_dim;

      const e = ensembles.slice(e_start, e_start + ensemble_dim);
      const q = queries.slice(q_start, q_start + query_dim);

      const { grad, confidence, loss } = this.critique(e, q);

      for (let i = 0; i < ensemble_dim; i++) {
        grads[e_start + i] = grad[i];
      }
      confidences.push(confidence);
      losses.push(loss);
    }

    return { grads, confidences, losses };
  }

  /**
   * мӢ лў°лҸ„ кё°л°ҳ мқҳмӮ¬кІ°м •
   */
  should_refine(confidence: number): boolean {
    return confidence < this.confidence_threshold;
  }

  /**
   * к°ңм„  н•„мҡ”лҸ„ м җмҲҳ (0: мҷ„лІҪ, 1: мҷ„м „нһҲ мһҳлӘ»лҗЁ)
   */
  refinement_score(confidence: number): number {
    return Math.max(0, 1 - confidence);
  }

  /**
   * к·ёлһҳл””м–ёнҠё кё°л°ҳ мҡ°л ӨлҸ„ (concern score)
   * к·ёлһҳл””м–ёнҠё нҒ¬кё°к°Җ нҒҙмҲҳлЎқ лӘЁлҚёмқҙ л¶Ҳнҷ•мӢӨ
   */
  concern_score(grad: Tensor): number {
    const norm = TensorOps.l2_norm(grad);
    return Math.min(1, norm / this.grad_normalization);
  }

  /**
   * к·ёлһҳл””м–ёнҠё л°©н–Ҙ (к°ңм„  л°©н–Ҙ)
   */
  improvement_direction(grad: Tensor): Tensor {
    return TensorOps.scale(grad, -1); // -вҲҮL л°©н–ҘмңјлЎң к°ңм„ 
  }

  /**
   * мөңлҢҖ к·ёлһҳл””м–ёнҠё мҡ”мҶҢ
   */
  max_gradient_component(grad: Tensor): number {
    return TensorOps.max_norm(grad);
  }

  /**
   * к·ёлһҳл””м–ёнҠё л¶„нҸ¬ нҶөкі„
   */
  gradient_stats(grad: Tensor): {
    mean: number;
    std: number;
    max: number;
    min: number;
  } {
    const abs_grad = TensorOps.abs(grad);
    const mean = TensorOps.mean(abs_grad);
    const std = TensorOps.std(abs_grad);
    const max = TensorOps.max(abs_grad);
    let min = abs_grad[0];
    for (let i = 1; i < abs_grad.length; i++) {
      min = Math.min(min, abs_grad[i]);
    }

    return { mean, std, max, min };
  }
}

/**
 * кі кёү л№„нҢҗ лӘЁл“Ҳ
 */
export class AdvancedCritiqueModule extends CritiqueModule {
  /**
   * мҳҲмёЎ л¶Ҳнҷ•мӢӨм„ұ м¶”м • (ensemble н‘ңмӨҖнҺём°Ё)
   */
  predict_uncertainty(ensemble: Tensor): number {
    return TensorOps.std(ensemble);
  }

  /**
   * мӢ лў°лҸ„ мһ¬кі„мӮ° (лӢӨмӨ‘ кё°мӨҖ)
   */
  critique_advanced(ensemble: Tensor, query: Tensor): {
    grad: Tensor;
    confidence: number;
    loss: number;
    uncertainty: number;
    concern: number;
  } {
    const { grad, confidence, loss } = this.critique(ensemble, query);
    const uncertainty = this.predict_uncertainty(ensemble);
    const concern = this.concern_score(grad);

    return { grad, confidence, loss, uncertainty, concern };
  }

  /**
   * лӢӨмӨ‘ мҶҗмӢӨ н•ЁмҲҳ кІ°н•©
   */
  combined_critique(
    ensemble: Tensor,
    query: Tensor,
    loss_fns: { fn: LossFn; weight: number }[]
  ): {
    grad: Tensor;
    confidence: number;
    combined_loss: number;
  } {
    let combined_loss = 0;
    let combined_grad = TensorOps.zeros(ensemble.length);

    for (const { fn: loss_fn, weight } of loss_fns) {
      combined_loss += weight * loss_fn(ensemble, query);
    }

    // мҲҳм№ҳ лҜёл¶„мңјлЎң к·ёлһҳл””м–ёнҠё м¶”м •
    const eps = 1e-5;
    for (let i = 0; i < ensemble.length; i++) {
      const e_plus = TensorOps.copy(ensemble);
      const e_minus = TensorOps.copy(ensemble);
      e_plus[i] += eps;
      e_minus[i] -= eps;

      let loss_plus = 0;
      let loss_minus = 0;

      for (const { fn: loss_fn, weight } of loss_fns) {
        loss_plus += weight * loss_fn(e_plus, query);
        loss_minus += weight * loss_fn(e_minus, query);
      }

      combined_grad[i] = (loss_plus - loss_minus) / (2 * eps);
    }

    const grad_norm = TensorOps.l2_norm(combined_grad);
    const confidence = Math.max(
      0,
      1 - grad_norm / this.grad_normalization
    );

    return { grad: combined_grad, confidence, combined_loss };
  }
}

/**
 * кё°ліё мҶҗмӢӨ н•ЁмҲҳл“Ө
 */
export class StandardLosses {
  /**
   * MSE мҶҗмӢӨ: L = ||ensemble - target||^2 / n
   */
  static mse_loss(target: Tensor): LossFn {
    return (ensemble: Tensor, query: Tensor) => {
      let loss = 0;
      for (let i = 0; i < ensemble.length; i++) {
        const diff = ensemble[i] - target[i];
        loss += diff * diff;
      }
      return loss / ensemble.length;
    };
  }

  /**
   * MSE мҶҗмӢӨмқҳ к·ёлһҳл””м–ёнҠё
   */
  static mse_grad(target: Tensor): GradientFn {
    return (ensemble: Tensor, query: Tensor) => {
      const grad = new Float64Array(ensemble.length);
      for (let i = 0; i < ensemble.length; i++) {
        grad[i] = 2 * (ensemble[i] - target[i]) / ensemble.length;
      }
      return grad;
    };
  }

  /**
   * L1 мҶҗмӢӨ: L = ОЈ |ensemble - target| / n
   */
  static l1_loss(target: Tensor): LossFn {
    return (ensemble: Tensor, query: Tensor) => {
      let loss = 0;
      for (let i = 0; i < ensemble.length; i++) {
        loss += Math.abs(ensemble[i] - target[i]);
      }
      return loss / ensemble.length;
    };
  }

  /**
   * L1 мҶҗмӢӨмқҳ к·ёлһҳл””м–ёнҠё
   */
  static l1_grad(target: Tensor): GradientFn {
    return (ensemble: Tensor, query: Tensor) => {
      const grad = new Float64Array(ensemble.length);
      for (let i = 0; i < ensemble.length; i++) {
        const diff = ensemble[i] - target[i];
        grad[i] =
          (diff > 0 ? 1 : diff < 0 ? -1 : 0) / ensemble.length;
      }
      return grad;
    };
  }

  /**
   * Cross-Entropy мҶҗмӢӨ (л¶„лҘҳ)
   */
  static cross_entropy_loss(target: Tensor): LossFn {
    return (ensemble: Tensor, query: Tensor) => {
      let loss = 0;
      for (let i = 0; i < ensemble.length; i++) {
        // softmax нҷ•лҘ лЎң н•ҙм„қ
        const p = Math.max(1e-10, Math.min(1 - 1e-10, ensemble[i]));
        loss -= target[i] * Math.log(p) + (1 - target[i]) * Math.log(1 - p);
      }
      return loss / ensemble.length;
    };
  }

  /**
   * Cross-Entropy мҶҗмӢӨмқҳ к·ёлһҳл””м–ёнҠё
   */
  static cross_entropy_grad(target: Tensor): GradientFn {
    return (ensemble: Tensor, query: Tensor) => {
      const grad = new Float64Array(ensemble.length);
      for (let i = 0; i < ensemble.length; i++) {
        const p = Math.max(1e-10, Math.min(1 - 1e-10, ensemble[i]));
        grad[i] =
          (p - target[i]) / (p * (1 - p)) / ensemble.length;
      }
      return grad;
    };
  }

  /**
   * Huber мҶҗмӢӨ (лЎңлІ„мҠӨнҠён•ң мҶҗмӢӨ)
   */
  static huber_loss(target: Tensor, delta: number = 1.0): LossFn {
    return (ensemble: Tensor, query: Tensor) => {
      let loss = 0;
      for (let i = 0; i < ensemble.length; i++) {
        const diff = Math.abs(ensemble[i] - target[i]);
        if (diff <= delta) {
          loss += 0.5 * diff * diff;
        } else {
          loss += delta * (diff - 0.5 * delta);
        }
      }
      return loss / ensemble.length;
    };
  }

  /**
   * Huber мҶҗмӢӨмқҳ к·ёлһҳл””м–ёнҠё
   */
  static huber_grad(target: Tensor, delta: number = 1.0): GradientFn {
    return (ensemble: Tensor, query: Tensor) => {
      const grad = new Float64Array(ensemble.length);
      for (let i = 0; i < ensemble.length; i++) {
        const diff = ensemble[i] - target[i];
        if (Math.abs(diff) <= delta) {
          grad[i] = diff;
        } else {
          grad[i] = delta * (diff > 0 ? 1 : -1);
        }
      }
      return grad;
    };
  }
}

/**
 * PostMindLang Runtime: Sampler Module
 * нҶ нҒ° мғҳн”Ңл§Ғ (softmax + мһ„кі„к°’)
 */

import { Tensor, Matrix, TensorOps } from "./tensor";

/**
 * мғҳн”Ңл§Ғ кІ°кіј
 */
export interface SampleResult {
  token: number;
  prob: number;
  logit: number;
}

/**
 * мғҳн”Ңлҹ¬ лӘЁл“Ҳ
 */
export class Sampler {
  /**
   * м¶ңл Ҙ к°ҖмӨ‘м№ҳ: W_out вҲҲ в„қ^(256Г—vocab_size)
   */
  W_out: Matrix;

  /**
   * м¶ңл Ҙ нҺён–Ҙ: b_out вҲҲ в„қ^vocab_size
   */
  b_out: Tensor;

  /**
   * м–ҙнңҳ нҒ¬кё°
   */
  vocab_size: number;

  /**
   * мһ…л Ҙ м°Ёмӣҗ
   */
  input_dim: number;

  constructor(input_dim: number = 256, vocab_size: number = 50257) {
    // GPT-2 кё°ліё м–ҙнңҳ нҒ¬кё°: 50257
    this.input_dim = input_dim;
    this.vocab_size = vocab_size;

    // м¶ңл Ҙмёө мҙҲкё°нҷ” (Xavier)
    const scale = Math.sqrt(2.0 / (input_dim + vocab_size));
    this.W_out = TensorOps.randn(input_dim * vocab_size);
    for (let i = 0; i < this.W_out.length; i++) {
      this.W_out[i] *= scale;
    }

    this.b_out = TensorOps.zeros(vocab_size);
  }

  /**
   * Logits кі„мӮ°: logits = W_out @ ensemble + b_out
   */
  compute_logits(ensemble: Tensor): Tensor {
    const logits = TensorOps.matvec(
      this.W_out,
      ensemble,
      this.vocab_size,
      this.input_dim
    );
    return TensorOps.add(logits, this.b_out);
  }

  /**
   * кё°ліё мғҳн”Ңл§Ғ (greedy + мһ„кі„к°’)
   */
  sample(
    ensemble: Tensor,
    tau: number = 0.8,
    threshold: number = 0.9
  ): SampleResult {
    // 1. Logits кі„мӮ°
    const logits = this.compute_logits(ensemble);

    // 2. Softmax: p = softmax(logits / П„)
    const probs = TensorOps.softmax(logits, tau);

    // 3. мөңлҢ“к°’ нҷ•лҘ 
    const max_prob = TensorOps.max(probs);
    const max_idx = TensorOps.argmax(probs);

    // 4. мһ„кі„к°’ кё°л°ҳ мқҳмӮ¬кІ°м •
    if (max_prob > threshold) {
      // лҶ’мқҖ мӢ лў°лҸ„: greedy м„ нғқ
      return {
        token: max_idx,
        prob: max_prob,
        logit: logits[max_idx],
      };
    } else {
      // лӮ®мқҖ мӢ лў°лҸ„: нҷ•лҘ  л¶„нҸ¬м—җм„ң мғҳн”Ң
      const sampled_idx = this.multinomial_sample(probs);
      return {
        token: sampled_idx,
        prob: probs[sampled_idx],
        logit: logits[sampled_idx],
      };
    }
  }

  /**
   * лӢӨн•ӯ л¶„нҸ¬ мғҳн”Ңл§Ғ
   */
  private multinomial_sample(probs: Tensor): number {
    const cum_probs = new Float64Array(probs.length);
    cum_probs[0] = probs[0];
    for (let i = 1; i < probs.length; i++) {
      cum_probs[i] = cum_probs[i - 1] + probs[i];
    }

    const r = Math.random();
    for (let i = 0; i < cum_probs.length; i++) {
      if (r < cum_probs[i]) {
        return i;
      }
    }
    return probs.length - 1;
  }

  /**
   * Top-K мғҳн”Ңл§Ғ
   * нҷ•лҘ мқҙ лҶ’мқҖ Kк°ң нҶ нҒ°л§Ң кі л Ө
   */
  sample_top_k(
    ensemble: Tensor,
    k: number,
    tau: number = 0.8
  ): SampleResult {
    const logits = this.compute_logits(ensemble);
    const probs = TensorOps.softmax(logits, tau);

    // Top-K нҶ нҒ° м°ҫкё°
    const indices: { idx: number; prob: number }[] = [];
    for (let i = 0; i < probs.length; i++) {
      indices.push({ idx: i, prob: probs[i] });
    }
    indices.sort((a, b) => b.prob - a.prob);

    // Top-K нҷ•лҘ л§Ң мң м§Җ
    let top_k_sum = 0;
    for (let i = 0; i < Math.min(k, indices.length); i++) {
      top_k_sum += indices[i].prob;
    }

    const top_k_probs = new Float64Array(probs.length);
    for (let i = 0; i < Math.min(k, indices.length); i++) {
      top_k_probs[indices[i].idx] = indices[i].prob / top_k_sum;
    }

    // мғҳн”Ңл§Ғ
    const sampled_idx = this.multinomial_sample(top_k_probs);
    return {
      token: sampled_idx,
      prob: probs[sampled_idx],
      logit: logits[sampled_idx],
    };
  }

  /**
   * Top-P (nucleus) мғҳн”Ңл§Ғ
   * лҲ„м Ғ нҷ•лҘ мқҙ PлҘј мҙҲкіјн•ҳм§Җ м•Ҡмқ„ л•Ңк№Ңм§Җмқҳ нҶ нҒ°л§Ң кі л Ө
   */
  sample_top_p(
    ensemble: Tensor,
    p: number = 0.9,
    tau: number = 0.8
  ): SampleResult {
    const logits = this.compute_logits(ensemble);
    const probs = TensorOps.softmax(logits, tau);

    // нҷ•лҘ  лӮҙлҰјм°ЁмҲң м •л ¬
    const indices: { idx: number; prob: number }[] = [];
    for (let i = 0; i < probs.length; i++) {
      indices.push({ idx: i, prob: probs[i] });
    }
    indices.sort((a, b) => b.prob - a.prob);

    // лҲ„м Ғ нҷ•лҘ мқҙ pлҘј мҙҲкіјн•  л•Ңк№Ңм§Җмқҳ нҶ нҒ°л§Ң мң м§Җ
    let cum_prob = 0;
    const top_p_indices: number[] = [];
    for (const { idx, prob } of indices) {
      cum_prob += prob;
      top_p_indices.push(idx);
      if (cum_prob >= p) {
        break;
      }
    }

    const top_p_probs = new Float64Array(probs.length);
    let top_p_sum = 0;
    for (const idx of top_p_indices) {
      top_p_probs[idx] = probs[idx];
      top_p_sum += probs[idx];
    }

    // м •к·ңнҷ”
    for (const idx of top_p_indices) {
      top_p_probs[idx] /= top_p_sum;
    }

    // мғҳн”Ңл§Ғ
    const sampled_idx = this.multinomial_sample(top_p_probs);
    return {
      token: sampled_idx,
      prob: probs[sampled_idx],
      logit: logits[sampled_idx],
    };
  }

  /**
   * мҳЁлҸ„ кё°л°ҳ мғҳн”Ңл§Ғ
   * П„ > 1: лҚ” лӢӨм–‘н•ң мғҳн”Ң
   * П„ < 1: лҚ” кІ°м •лЎ м Ғ
   * П„ = 1: кё°ліё
   */
  sample_with_temperature(
    ensemble: Tensor,
    tau: number = 1.0
  ): SampleResult {
    const logits = this.compute_logits(ensemble);
    const probs = TensorOps.softmax(logits, tau);

    const sampled_idx = this.multinomial_sample(probs);
    return {
      token: sampled_idx,
      prob: probs[sampled_idx],
      logit: logits[sampled_idx],
    };
  }

  /**
   * к·ёлһҳл””м–ёнҠё кі„мӮ°
   */
  gradient(
    sample_result: SampleResult,
    ensemble: Tensor
  ): {
    dW_out: Matrix;
    db_out: Tensor;
    densemble: Tensor;
  } {
    // Cross-entropy мҶҗмӢӨ к·ёлһҳл””м–ёнҠё
    const logits = this.compute_logits(ensemble);
    const probs = TensorOps.softmax(logits, 1.0);

    // вҲӮL/вҲӮlogit_i = p_i - target_i
    // target_i = 1 if i == sample_result.token else 0
    const grad_logits = new Float64Array(this.vocab_size);
    for (let i = 0; i < this.vocab_size; i++) {
      grad_logits[i] =
        probs[i] - (i === sample_result.token ? 1 : 0);
    }

    // вҲӮL/вҲӮW_out = grad_logits вҠ— ensemble
    const dW_out = TensorOps.outer(ensemble, grad_logits);

    // вҲӮL/вҲӮb_out = grad_logits
    const db_out = TensorOps.copy(grad_logits);

    // вҲӮL/вҲӮensemble = W_out^T @ grad_logits
    const W_out_T = TensorOps.transpose(
      this.W_out,
      this.input_dim,
      this.vocab_size
    );
    const densemble = TensorOps.matvec(
      W_out_T,
      grad_logits,
      this.input_dim,
      this.vocab_size
    );

    return { dW_out, db_out, densemble };
  }

  /**
   * л°°м№ҳ к·ёлһҳл””м–ёнҠё
   */
  gradient_batch(
    samples: number[],
    ensembles: Float64Array,
    batch_size: number
  ): {
    dW_out: Matrix;
    db_out: Tensor;
    densembles: Float64Array;
  } {
    const dW_out = TensorOps.zeros(
      this.input_dim * this.vocab_size
    );
    const db_out = TensorOps.zeros(this.vocab_size);
    const densembles = TensorOps.zeros(
      batch_size * this.input_dim
    );

    for (let b = 0; b < batch_size; b++) {
      const e_start = b * this.input_dim;
      const ensemble = ensembles.slice(
        e_start,
        e_start + this.input_dim
      );

      const logits = this.compute_logits(ensemble);
      const probs = TensorOps.softmax(logits, 1.0);

      const grad_logits = new Float64Array(this.vocab_size);
      for (let i = 0; i < this.vocab_size; i++) {
        grad_logits[i] =
          probs[i] - (i === samples[b] ? 1 : 0);
      }

      // лҲ„м Ғ к·ёлһҳл””м–ёнҠё
      const outer_prod = TensorOps.outer(ensemble, grad_logits);
      for (let i = 0; i < dW_out.length; i++) {
        dW_out[i] += outer_prod[i];
      }

      for (let i = 0; i < this.vocab_size; i++) {
        db_out[i] += grad_logits[i];
      }

      const W_out_T = TensorOps.transpose(
        this.W_out,
        this.input_dim,
        this.vocab_size
      );
      const densemble = TensorOps.matvec(
        W_out_T,
        grad_logits,
        this.input_dim,
        this.vocab_size
      );

      for (let i = 0; i < this.input_dim; i++) {
        densembles[e_start + i] = densemble[i];
      }
    }

    return { dW_out, db_out, densembles };
  }

  /**
   * к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё
   */
  update(
    dW_out: Matrix,
    db_out: Tensor,
    learning_rate: number
  ): void {
    for (let i = 0; i < this.W_out.length; i++) {
      this.W_out[i] -= learning_rate * dW_out[i];
    }

    for (let i = 0; i < this.b_out.length; i++) {
      this.b_out[i] -= learning_rate * db_out[i];
    }
  }

  /**
   * мғҒмң„ нҷ•лҘ  нҶ нҒ° мЎ°нҡҢ
   */
  top_tokens(ensemble: Tensor, k: number = 10): {
    token: number;
    prob: number;
  }[] {
    const logits = this.compute_logits(ensemble);
    const probs = TensorOps.softmax(logits, 1.0);

    const tokens: { token: number; prob: number }[] = [];
    for (let i = 0; i < probs.length; i++) {
      tokens.push({ token: i, prob: probs[i] });
    }

    tokens.sort((a, b) => b.prob - a.prob);
    return tokens.slice(0, Math.min(k, tokens.length));
  }

  /**
   * м—”нҠёлЎңн”ј кі„мӮ° (мғҳн”Ңл§Ғ лӢӨм–‘м„ұ мёЎм •)
   */
  entropy(ensemble: Tensor): number {
    const logits = this.compute_logits(ensemble);
    const probs = TensorOps.softmax(logits, 1.0);

    let entropy = 0;
    for (let i = 0; i < probs.length; i++) {
      if (probs[i] > 1e-10) {
        entropy -= probs[i] * Math.log(probs[i]);
      }
    }

    return entropy;
  }

  /**
   * м§Ғл ¬нҷ”
   */
  serialize(): {
    W_out: number[];
    b_out: number[];
    vocab_size: number;
    input_dim: number;
  } {
    return {
      W_out: Array.from(this.W_out),
      b_out: Array.from(this.b_out),
      vocab_size: this.vocab_size,
      input_dim: this.input_dim,
    };
  }

  /**
   * м—ӯм§Ғл ¬нҷ”
   */
  static deserialize(data: {
    W_out: number[];
    b_out: number[];
    vocab_size: number;
    input_dim: number;
  }): Sampler {
    const sampler = new Sampler(data.input_dim, data.vocab_size);
    sampler.W_out = new Float64Array(data.W_out);
    sampler.b_out = new Float64Array(data.b_out);
    return sampler;
  }

  /**
   * л””лІ„к№… м •ліҙ
   */
  debug_info(): string {
    const w_norm = TensorOps.l2_norm(this.W_out);
    const b_norm = TensorOps.l2_norm(this.b_out);
    return (
      `Sampler(${this.input_dim}вҶ’${this.vocab_size}): ` +
      `||W_out||=${w_norm.toFixed(4)}, ||b_out||=${b_norm.toFixed(4)}`
    );
  }
}

/**
 * PostMindLang Runtime: Differentiable Operations
 * лҜёл¶„ к°ҖлҠҘн•ң м—°мӮ°л“Өкіј м—ӯм „нҢҢ кө¬нҳ„
 */

import { Tensor, Matrix, TensorOps } from "./tensor";

/**
 * м—ӯм „нҢҢ н•ЁмҲҳ нғҖмһ…
 */
export type BackwardFn = (grad_output: Tensor) => {
  [key: string]: Tensor | Matrix;
};

/**
 * кі„мӮ° к·ёлһҳн”„ л…ёл“ң
 */
export interface ComputeNode {
  value: Tensor | Matrix;
  backward: BackwardFn;
  inputs: ComputeNode[];
  operation: string;
}

/**
 * н…Ңмқҙн”„ кё°л°ҳ мһҗлҸҷ лҜёл¶„
 */
export class ComputationGraph {
  nodes: ComputeNode[] = [];
  tape: ComputeNode[] = [];

  /**
   * мҲңм „нҢҢ
   */
  forward_pass(
    input: Tensor,
    operations: Array<(x: Tensor) => { result: Tensor; backward: BackwardFn }>
  ): Tensor {
    let current = input;
    for (const op of operations) {
      const { result, backward } = op(current);
      const node: ComputeNode = {
        value: result,
        backward,
        inputs: [],
        operation: "custom",
      };
      this.tape.push(node);
      current = result;
    }
    return current;
  }

  /**
   * м—ӯм „нҢҢ
   */
  backward(loss_gradient: Tensor): void {
    let grad = loss_gradient;
    for (let i = this.tape.length - 1; i >= 0; i--) {
      const node = this.tape[i];
      const grads = node.backward(grad);
      grad = grads.input as Tensor;
    }
  }

  /**
   * к·ёлһҳн”„ мҙҲкё°нҷ”
   */
  reset(): void {
    this.nodes = [];
    this.tape = [];
  }
}

/**
 * лҜёл¶„ к°ҖлҠҘн•ң м—°мӮ° лқјмқҙлёҢлҹ¬лҰ¬
 */
export class DifferentiableOps {
  /**
   * ReLU: y = max(0, x), вҲӮy/вҲӮx = x > 0 ? 1 : 0
   */
  static relu(x: Tensor): { result: Tensor; backward: BackwardFn } {
    const y = TensorOps.relu(x);

    const backward: BackwardFn = (grad_y: Tensor) => {
      const grad_x = TensorOps.grad_relu(grad_y, x);
      return { input: grad_x };
    };

    return { result: y, backward };
  }

  /**
   * Sigmoid: y = 1/(1+exp(-x)), вҲӮy/вҲӮx = y*(1-y)
   */
  static sigmoid(x: Tensor): {
    result: Tensor;
    backward: BackwardFn;
  } {
    const y = TensorOps.sigmoid(x);

    const backward: BackwardFn = (grad_y: Tensor) => {
      const grad_x = TensorOps.grad_sigmoid(grad_y, y);
      return { input: grad_x };
    };

    return { result: y, backward };
  }

  /**
   * Softmax: y_i = exp(x_i/П„)/ОЈexp(x_j/П„)
   */
  static softmax(x: Tensor, tau: number = 1.0): {
    result: Tensor;
    backward: BackwardFn;
  } {
    const y = TensorOps.softmax(x, tau);

    const backward: BackwardFn = (grad_y: Tensor) => {
      // Softmax к·ёлһҳл””м–ёнҠё: вҲӮL/вҲӮx_i = y_i * (вҲӮL/вҲӮy_i - ОЈ y_j * вҲӮL/вҲӮy_j)
      const grad_x = TensorOps.grad_softmax(grad_y, y);
      return { input: grad_x };
    };

    return { result: y, backward };
  }

  /**
   * н–үл ¬-лІЎн„° кіұм…Ҳ: y = A @ x
   */
  static matvec(A: Matrix, x: Tensor, m: number, n: number): {
    result: Tensor;
    backward: BackwardFn;
  } {
    const y = TensorOps.matvec(A, x, m, n);

    const backward: BackwardFn = (grad_y: Tensor) => {
      // вҲӮL/вҲӮA = grad_y вҠ— x
      const grad_A = TensorOps.outer(x, grad_y);

      // вҲӮL/вҲӮx = A^T @ grad_y
      const A_T = TensorOps.transpose(A, m, n);
      const grad_x = TensorOps.matvec(A_T, grad_y, n, m);

      return { A: grad_A, x: grad_x };
    };

    return { result: y, backward };
  }

  /**
   * лІЎн„° лҚ§м…Ҳ: c = a + b
   */
  static add(a: Tensor, b: Tensor): {
    result: Tensor;
    backward: BackwardFn;
  } {
    const c = TensorOps.add(a, b);

    const backward: BackwardFn = (grad_c: Tensor) => {
      // вҲӮL/вҲӮa = grad_c
      // вҲӮL/вҲӮb = grad_c
      return { a: TensorOps.copy(grad_c), b: TensorOps.copy(grad_c) };
    };

    return { result: c, backward };
  }

  /**
   * мҠӨм№јлқј кіұм…Ҳ: b = Оұ * a
   */
  static scale(a: Tensor, alpha: number): {
    result: Tensor;
    backward: BackwardFn;
  } {
    const b = TensorOps.scale(a, alpha);

    const backward: BackwardFn = (grad_b: Tensor) => {
      // вҲӮL/вҲӮa = Оұ * grad_b
      const grad_a = TensorOps.scale(grad_b, alpha);
      return { a: grad_a, alpha: TensorOps.dot(grad_b, a) };
    };

    return { result: b, backward };
  }

  /**
   * лӮҙм Ғ: y = <a, b>
   */
  static dot(a: Tensor, b: Tensor): {
    result: number;
    backward: BackwardFn;
  } {
    const y = TensorOps.dot(a, b);

    const backward: BackwardFn = (grad_y: number) => {
      // вҲӮL/вҲӮa = grad_y * b
      const grad_a = TensorOps.scale(b, grad_y);

      // вҲӮL/вҲӮb = grad_y * a
      const grad_b = TensorOps.scale(a, grad_y);

      return { a: grad_a, b: grad_b };
    };

    return {
      result: y,
      backward: backward as BackwardFn,
    };
  }

  /**
   * мҷём Ғ: C = a вҠ— b
   */
  static outer(a: Tensor, b: Tensor): {
    result: Matrix;
    backward: BackwardFn;
  } {
    const C = TensorOps.outer(a, b);

    const backward: BackwardFn = (grad_C: Matrix) => {
      // вҲӮL/вҲӮa_i = ОЈ_j grad_C_ij * b_j
      const grad_a = new Float64Array(a.length);
      for (let i = 0; i < a.length; i++) {
        let sum = 0;
        for (let j = 0; j < b.length; j++) {
          sum += grad_C[i * b.length + j] * b[j];
        }
        grad_a[i] = sum;
      }

      // вҲӮL/вҲӮb_j = ОЈ_i grad_C_ij * a_i
      const grad_b = new Float64Array(b.length);
      for (let j = 0; j < b.length; j++) {
        let sum = 0;
        for (let i = 0; i < a.length; i++) {
          sum += grad_C[i * b.length + j] * a[i];
        }
        grad_b[j] = sum;
      }

      return { a: grad_a, b: grad_b };
    };

    return { result: C, backward };
  }

  /**
   * мӣҗмҶҢлі„ кіұм…Ҳ: c = a вҠҷ b
   */
  static elementwise_mult(a: Tensor, b: Tensor): {
    result: Tensor;
    backward: BackwardFn;
  } {
    const c = TensorOps.elementwise_mult(a, b);

    const backward: BackwardFn = (grad_c: Tensor) => {
      // вҲӮL/вҲӮa = grad_c вҠҷ b
      const grad_a = TensorOps.elementwise_mult(grad_c, b);

      // вҲӮL/вҲӮb = grad_c вҠҷ a
      const grad_b = TensorOps.elementwise_mult(grad_c, a);

      return { a: grad_a, b: grad_b };
    };

    return { result: c, backward };
  }

  /**
   * L2 л…ёлҰ„: y = ||x||_2
   */
  static l2_norm(x: Tensor): {
    result: number;
    backward: BackwardFn;
  } {
    const y = TensorOps.l2_norm(x);

    const backward: BackwardFn = (grad_y: number) => {
      // вҲӮL/вҲӮx = (grad_y / ||x||) * x
      const grad_x = TensorOps.scale(x, grad_y / (y + 1e-10));
      return { x: grad_x };
    };

    return {
      result: y,
      backward: backward as BackwardFn,
    };
  }

  /**
   * Exp: y = exp(x)
   */
  static exp(x: Tensor): { result: Tensor; backward: BackwardFn } {
    const y = TensorOps.exp(x);

    const backward: BackwardFn = (grad_y: Tensor) => {
      // вҲӮL/вҲӮx = grad_y вҠҷ y
      const grad_x = TensorOps.elementwise_mult(grad_y, y);
      return { x: grad_x };
    };

    return { result: y, backward };
  }

  /**
   * Log: y = log(x)
   */
  static log(x: Tensor): { result: Tensor; backward: BackwardFn } {
    const y = TensorOps.log(x);

    const backward: BackwardFn = (grad_y: Tensor) => {
      // вҲӮL/вҲӮx = grad_y Г· x
      const grad_x = TensorOps.elementwise_div(grad_y, x);
      return { x: grad_x };
    };

    return { result: y, backward };
  }
}

/**
 * м—ӯм „нҢҢ м—”м§„ (м—ӯлӘЁл“ң мһҗлҸҷ лҜёл¶„)
 */
export class ReverseMode {
  /**
   * кі„мӮ° н…Ңмқҙн”„
   */
  tape: ComputeNode[] = [];

  /**
   * ліҖмҲҳ м ҖмһҘмҶҢ
   */
  variables: Map<string, { value: Tensor | Matrix; grad: Tensor | Matrix }> =
    new Map();

  /**
   * ліҖмҲҳ мғқм„ұ
   */
  variable(
    name: string,
    value: Tensor | Matrix
  ): string {
    this.variables.set(name, {
      value: TensorOps.copy(value),
      grad: TensorOps.zeros(value.length),
    });
    return name;
  }

  /**
   * мҲңм „нҢҢ
   */
  forward(fn: (vars: typeof this.variables) => Tensor): Tensor {
    return fn(this.variables);
  }

  /**
   * м—ӯм „нҢҢ
   */
  backward(loss_grad: Tensor): void {
    // н…Ңмқҙн”„мқҳ м—ӯмҲңмңјлЎң м—ӯм „нҢҢ
    for (let i = this.tape.length - 1; i >= 0; i--) {
      const node = this.tape[i];
      const grads = node.backward(loss_grad);

      // мһ…л Ҙ ліҖмҲҳ к·ёлһҳл””м–ёнҠё лҲ„м Ғ
      for (const input of node.inputs) {
        // к·ёлһҳл””м–ёнҠё лҲ„м Ғ лЎңм§Ғ
      }
    }
  }

  /**
   * к·ёлһҳл””м–ёнҠё мЎ°нҡҢ
   */
  get_gradient(name: string): Tensor | Matrix | undefined {
    return this.variables.get(name)?.grad;
  }

  /**
   * к·ёлһҳл””м–ёнҠё мҙҲкё°нҷ”
   */
  zero_grad(): void {
    for (const [_, var_data] of this.variables) {
      var_data.grad.fill(0);
    }
  }

  /**
   * н…Ңмқҙн”„ мҙҲкё°нҷ”
   */
  reset(): void {
    this.tape = [];
    this.variables.clear();
  }
}

/**
 * мҲҳм№ҳ лҜёл¶„мқ„ нҶөн•ң к·ёлһҳл””м–ёнҠё кІҖмҰқ
 */
export class GradientChecker {
  /**
   * мҲҳм№ҳ к·ёлһҳл””м–ёнҠё кі„мӮ°
   */
  static numerical_gradient(
    fn: (x: Tensor) => number,
    x: Tensor,
    eps: number = 1e-5
  ): Tensor {
    const grad = new Float64Array(x.length);

    for (let i = 0; i < x.length; i++) {
      const x_plus = TensorOps.copy(x);
      const x_minus = TensorOps.copy(x);

      x_plus[i] += eps;
      x_minus[i] -= eps;

      const f_plus = fn(x_plus);
      const f_minus = fn(x_minus);

      grad[i] = (f_plus - f_minus) / (2 * eps);
    }

    return grad;
  }

  /**
   * к·ёлһҳл””м–ёнҠё кІҖмҰқ
   */
  static check_gradient(
    fn: (x: Tensor) => number,
    grad_fn: (x: Tensor) => Tensor,
    x: Tensor,
    eps: number = 1e-5,
    tolerance: number = 1e-3
  ): {
    passed: boolean;
    max_error: number;
    errors: number[];
  } {
    const grad_analytical = grad_fn(x);
    const grad_numerical = this.numerical_gradient(fn, x, eps);

    const errors: number[] = [];
    let max_error = 0;

    for (let i = 0; i < x.length; i++) {
      const error = Math.abs(
        grad_analytical[i] - grad_numerical[i]
      ) /
        (Math.abs(grad_analytical[i]) +
          Math.abs(grad_numerical[i]) +
          1e-8);
      errors.push(error);
      max_error = Math.max(max_error, error);
    }

    return {
      passed: max_error < tolerance,
      max_error,
      errors,
    };
  }

  /**
   * л°°м№ҳ к·ёлһҳл””м–ёнҠё кІҖмҰқ
   */
  static check_batch_gradient(
    fn: (X: Float64Array) => number,
    grad_fn: (X: Float64Array) => Float64Array,
    X: Float64Array,
    batch_size: number,
    sample_size: number = 10
  ): {
    passed: boolean;
    avg_error: number;
    max_error: number;
  } {
    let total_error = 0;
    let max_error = 0;

    for (let s = 0; s < sample_size; s++) {
      const i = Math.floor(Math.random() * X.length);

      const grad_analytical = grad_fn(X);
      const grad_numerical = this.numerical_gradient(fn, X);

      const error = Math.abs(
        grad_analytical[i] - grad_numerical[i]
      ) /
        (Math.abs(grad_analytical[i]) +
          Math.abs(grad_numerical[i]) +
          1e-8);
      total_error += error;
      max_error = Math.max(max_error, error);
    }

    const avg_error = total_error / sample_size;

    return {
      passed: max_error < 1e-3,
      avg_error,
      max_error,
    };
  }
}

/**
 * PostMindLang Runtime: Main Execution Engine
 * PostMindLang лҹ°нғҖмһ„ кө¬нҳ„
 */

import { Tensor, TensorOps } from "./tensor";
import { QueryEncoder } from "./encoding";
import { PathExecutor } from "./paths";
import { EnsembleModule } from "./ensemble";
import { CritiqueModule, StandardLosses } from "./critique";
import { Sampler, SampleResult } from "./sampler";

/**
 * лҹ°нғҖмһ„ кө¬м„ұ мҳөм…ҳ
 */
export interface RuntimeConfig {
  query_dim: number;
  encoder_dim: number;
  path_dim: number;
  vocab_size: number;
  temperature: number;
  confidence_threshold: number;
  max_iterations: number;
}

/**
 * мӢӨн–ү кІ°кіј
 */
export interface ExecutionResult {
  token: number;
  confidence: number;
  iterations: number;
  refined: boolean;
  tokens: number[];
  probabilities: number[];
  path_weights: { a: number; b: number; c: number };
  timing: {
    encode: number;
    paths: number;
    ensemble: number;
    critique: number;
    sample: number;
    refine: number;
  };
}

/**
 * нӣҲл Ё мғҒнғң
 */
export interface TrainingState {
  loss: number;
  accuracy: number;
  iteration: number;
  learning_rate: number;
}

/**
 * PostMindLang лҹ°нғҖмһ„
 * мҷ„м „нһҲ лҜёл¶„ к°ҖлҠҘн•ң мӢ кІҪл§қ кё°л°ҳ н…ҚмҠӨнҠё мғқм„ұ
 */
export class PostMindLangRuntime {
  /**
   * лӘЁл“Ҳ кө¬м„ұ
   */
  encoder: QueryEncoder;
  paths: PathExecutor;
  ensemble: EnsembleModule;
  critique: CritiqueModule;
  sampler: Sampler;

  /**
   * м„Өм •
   */
  config: RuntimeConfig;

  /**
   * нҶөкі„
   */
  stats: {
    total_executions: number;
    total_refinements: number;
    avg_confidence: number;
    avg_iterations: number;
  };

  constructor(config?: Partial<RuntimeConfig>) {
    this.config = {
      query_dim: 768,
      encoder_dim: 512,
      path_dim: 256,
      vocab_size: 50257,
      temperature: 0.8,
      confidence_threshold: 0.8,
      max_iterations: 3,
      ...config,
    };

    // лӘЁл“Ҳ мҙҲкё°нҷ”
    this.encoder = new QueryEncoder(
      this.config.query_dim,
      this.config.encoder_dim
    );

    this.paths = new PathExecutor(
      this.config.encoder_dim,
      this.config.path_dim
    );

    this.ensemble = new EnsembleModule(
      this.config.query_dim,
      this.config.temperature
    );

    // кё°ліё мҶҗмӢӨ н•ЁмҲҳ (MSE)
    const target = TensorOps.zeros(this.config.path_dim);
    const loss_fn = StandardLosses.mse_loss(target);
    const grad_fn = StandardLosses.mse_grad(target);

    this.critique = new CritiqueModule(
      loss_fn,
      grad_fn,
      this.config.confidence_threshold
    );

    this.sampler = new Sampler(
      this.config.path_dim,
      this.config.vocab_size
    );

    // нҶөкі„ мҙҲкё°нҷ”
    this.stats = {
      total_executions: 0,
      total_refinements: 0,
      avg_confidence: 0,
      avg_iterations: 0,
    };
  }

  /**
   * лӢЁмқј нҶ нҒ° мғқм„ұ (л©”мқё мӢӨн–ү лЈЁн”„)
   */
  async execute(query: Tensor): Promise<ExecutionResult> {
    const timing: any = {};
    const tokens: number[] = [];
    const probabilities: number[] = [];

    // 1. мҝјлҰ¬ мқёмҪ”л”©
    const t_start = performance.now();
    const z = this.encoder.encode(query);
    timing.encode = performance.now() - t_start;

    // 2. 3к°ң кІҪлЎң лі‘л ¬ мӢӨн–ү
    const t_paths_start = performance.now();
    const { z_a, z_b, z_c } = this.paths.execute_parallel(z);
    timing.paths = performance.now() - t_paths_start;

    // 3. м Ғмқ‘нҳ• к°ҖмӨ‘м№ҳ кі„мӮ°
    const t_ensemble_start = performance.now();
    const w = this.ensemble.compute_weights(query);
    const path_weights = { a: w[0], b: w[1], c: w[2] };

    // 4. м•ҷмғҒлё” кІ°н•©
    const e = this.ensemble.combine(w, z_a, z_b, z_c);
    timing.ensemble = performance.now() - t_ensemble_start;

    // 5. мһҗк°Җ л№„нҢҗ
    const t_critique_start = performance.now();
    const { grad, confidence } = this.critique.critique(e, query);
    timing.critique = performance.now() - t_critique_start;

    // 6. мғҳн”Ңл§Ғ лҳҗлҠ” к°ңм„ 
    let refined = false;
    let iterations = 1;
    let current_e = e;
    let current_confidence = confidence;

    const t_sample_start = performance.now();
    if (current_confidence > this.config.confidence_threshold) {
      // мӢ лў°лҸ„к°Җ лҶ’мқҢ: к·ёлҰ¬л”” мғҳн”Ңл§Ғ
      const sample = this.sampler.sample(
        current_e,
        this.config.temperature,
        0.9
      );
      tokens.push(sample.token);
      probabilities.push(sample.prob);
    } else {
      // мӢ лў°лҸ„к°Җ лӮ®мқҢ: к°ңм„  н•„мҡ”
      refined = true;
      const t_refine_start = performance.now();

      // л°ҳліөм Ғ к°ңм„  (к·ёлһҳл””м–ёнҠё мғҒмҠ№)
      for (let iter = 0; iter < this.config.max_iterations; iter++) {
        // e' = e - Оұ * вҲҮL (к·ёлһҳл””м–ёнҠё к°җмҶҢ)
        const alpha = 0.1 * (1 - iter / this.config.max_iterations);
        const grad_scaled = TensorOps.scale(grad, -alpha);
        current_e = TensorOps.add(current_e, grad_scaled);

        // м—…лҚ°мқҙнҠёлҗң мӢ лў°лҸ„ кі„мӮ°
        const { confidence: new_conf } = this.critique.critique(
          current_e,
          query
        );
        current_confidence = new_conf;
        iterations = iter + 2;

        // м¶©л¶„нһҲ к°ңм„ лҗҳм—Ҳмңјл©ҙ мӨ‘лӢЁ
        if (current_confidence > this.config.confidence_threshold) {
          break;
        }
      }

      timing.refine = performance.now() - t_refine_start;

      // мөңмў… мғҳн”Ңл§Ғ
      const sample = this.sampler.sample(
        current_e,
        this.config.temperature,
        0.8
      );
      tokens.push(sample.token);
      probabilities.push(sample.prob);
    }
    timing.sample = performance.now() - t_sample_start;

    // нҶөкі„ м—…лҚ°мқҙнҠё
    this.stats.total_executions++;
    this.stats.total_refinements += refined ? 1 : 0;
    this.stats.avg_confidence =
      (this.stats.avg_confidence * (this.stats.total_executions - 1) +
        current_confidence) /
      this.stats.total_executions;
    this.stats.avg_iterations =
      (this.stats.avg_iterations * (this.stats.total_executions - 1) +
        iterations) /
      this.stats.total_executions;

    return {
      token: tokens[0],
      confidence: current_confidence,
      iterations,
      refined,
      tokens,
      probabilities,
      path_weights,
      timing,
    };
  }

  /**
   * мӢңнҖҖмҠӨ мғқм„ұ
   */
  async generate(
    query: Tensor,
    max_length: number = 10
  ): Promise<{
    tokens: number[];
    confidences: number[];
    results: ExecutionResult[];
  }> {
    const tokens: number[] = [];
    const confidences: number[] = [];
    const results: ExecutionResult[] = [];

    for (let i = 0; i < max_length; i++) {
      const result = await this.execute(query);
      tokens.push(result.token);
      confidences.push(result.confidence);
      results.push(result);

      // мӢ лў°лҸ„к°Җ л„Ҳл¬ҙ лӮ®мңјл©ҙ мғқм„ұ мӨ‘лӢЁ
      if (result.confidence < 0.2) {
        break;
      }
    }

    return { tokens, confidences, results };
  }

  /**
   * л°°м№ҳ м¶”лЎ 
   */
  async infer_batch(
    queries: Float64Array,
    batch_size: number
  ): Promise<{
    tokens: number[];
    confidences: number[];
  }> {
    const tokens: number[] = [];
    const confidences: number[] = [];

    const query_dim = this.config.query_dim;

    for (let b = 0; b < batch_size; b++) {
      const q_start = b * query_dim;
      const q = queries.slice(q_start, q_start + query_dim);
      const result = await this.execute(q);

      tokens.push(result.token);
      confidences.push(result.confidence);
    }

    return { tokens, confidences };
  }

  /**
   * м „мІҙ к·ёлһҳл””м–ёнҠё кі„мӮ° (нӣҲл Ёмҡ©)
   */
  backward(
    sample_token: number,
    ensemble: Tensor,
    query: Tensor,
    z: Tensor,
    z_a: Tensor,
    z_b: Tensor,
    z_c: Tensor,
    w: Tensor
  ): {
    encoder_grads: any;
    path_grads: any;
    ensemble_grads: any;
    sampler_grads: any;
  } {
    // 1. мғҳн”Ңлҹ¬ к·ёлһҳл””м–ёнҠё
    const sample_result: SampleResult = {
      token: sample_token,
      prob: 0.5,
      logit: 0,
    };
    const {
      dW_out,
      db_out,
      densemble: grad_ensemble,
    } = this.sampler.gradient(sample_result, ensemble);

    // 2. м•ҷмғҒлё” к·ёлһҳл””м–ёнҠё
    const { grad_w, grad_z_a, grad_z_b, grad_z_c } =
      this.ensemble.gradient(grad_ensemble, w, z_a, z_b, z_c);

    // 3. кІҪлЎң к·ёлһҳл””м–ёнҠё
    const path_grads = this.paths.gradient_all(
      grad_z_a,
      grad_z_b,
      grad_z_c,
      z
    );

    // 4. к°ҖмӨ‘м№ҳ н•ЁмҲҳ к·ёлһҳл””м–ёнҠё
    const { dW_weight, db_weight, dq: grad_q_weight } =
      this.ensemble.gradient_weight_fn(grad_w, query);

    // 5. мқёмҪ”лҚ” к·ёлһҳл””м–ёнҠё
    const { dW: dW_enc, db: db_enc, dq: grad_q_enc } =
      this.encoder.gradient(path_grads.dz, query);

    // мөңмў… мҝјлҰ¬ к·ёлһҳл””м–ёнҠё
    const grad_q = TensorOps.add(grad_q_weight, grad_q_enc);

    return {
      encoder_grads: { dW: dW_enc, db: db_enc, dq: grad_q },
      path_grads,
      ensemble_grads: { dW_weight, db_weight },
      sampler_grads: { dW_out, db_out },
    };
  }

  /**
   * нӣҲл Ё мҠӨн…қ
   */
  train_step(
    query: Tensor,
    target_token: number,
    learning_rate: number = 0.001
  ): TrainingState {
    // мҲңм „нҢҢ
    const z = this.encoder.encode(query);
    const { z_a, z_b, z_c } = this.paths.execute_parallel(z);
    const w = this.ensemble.compute_weights(query);
    const ensemble = this.ensemble.combine(w, z_a, z_b, z_c);

    // м—ӯм „нҢҢ
    const grads = this.backward(
      target_token,
      ensemble,
      query,
      z,
      z_a,
      z_b,
      z_c,
      w
    );

    // к°ҖмӨ‘м№ҳ м—…лҚ°мқҙнҠё
    this.encoder.update(
      grads.encoder_grads.dW,
      grads.encoder_grads.db,
      learning_rate
    );

    this.paths.update(
      grads.path_grads.dP_a,
      grads.path_grads.db_a,
      grads.path_grads.dP_b,
      grads.path_grads.db_b,
      grads.path_grads.dP_c,
      grads.path_grads.db_c,
      learning_rate
    );

    this.ensemble.update(
      grads.ensemble_grads.dW_weight,
      grads.ensemble_grads.db_weight,
      learning_rate
    );

    this.sampler.update(
      grads.sampler_grads.dW_out,
      grads.sampler_grads.db_out,
      learning_rate
    );

    // мҶҗмӢӨ кі„мӮ° (к°„лӢЁнһҲ: н‘ңмӨҖнҺём°Ёмқҳ м—ӯн•ЁмҲҳ)
    const loss = TensorOps.std(ensemble);

    return {
      loss,
      accuracy: 0.5, // н”Ңл ҲмқҙмҠӨнҷҖлҚ”
      iteration: this.stats.total_executions,
      learning_rate,
    };
  }

  /**
   * м—җнҸ¬нҒ¬ нӣҲл Ё
   */
  train_epoch(
    queries: Float64Array,
    targets: number[],
    batch_size: number,
    learning_rate: number = 0.001
  ): {
    avg_loss: number;
    iterations: number;
  } {
    let total_loss = 0;
    const num_batches = Math.ceil(targets.length / batch_size);
    const query_dim = this.config.query_dim;

    for (let batch = 0; batch < num_batches; batch++) {
      const start_idx = batch * batch_size;
      const end_idx = Math.min(start_idx + batch_size, targets.length);

      for (let i = start_idx; i < end_idx; i++) {
        const q_start = i * query_dim;
        const q = queries.slice(q_start, q_start + query_dim);

        const state = this.train_step(q, targets[i], learning_rate);
        total_loss += state.loss;
      }
    }

    return {
      avg_loss: total_loss / targets.length,
      iterations: targets.length,
    };
  }

  /**
   * лӘЁлҚё м ҖмһҘ
   */
  save(): {
    encoder: ReturnType<typeof QueryEncoder.prototype.serialize>;
    paths: ReturnType<typeof PathExecutor.prototype.serialize>;
    ensemble: ReturnType<typeof EnsembleModule.prototype.serialize>;
    sampler: ReturnType<typeof Sampler.prototype.serialize>;
  } {
    return {
      encoder: this.encoder.serialize(),
      paths: this.paths.serialize(),
      ensemble: this.ensemble.serialize(),
      sampler: this.sampler.serialize(),
    };
  }

  /**
   * лӘЁлҚё ліөмӣҗ
   */
  static load(
    data: ReturnType<typeof PostMindLangRuntime.prototype.save>,
    config?: Partial<RuntimeConfig>
  ): PostMindLangRuntime {
    const runtime = new PostMindLangRuntime(config);
    runtime.encoder = QueryEncoder.deserialize(data.encoder);
    runtime.paths = PathExecutor.deserialize(data.paths);
    runtime.ensemble = EnsembleModule.deserialize(data.ensemble);
    runtime.sampler = Sampler.deserialize(data.sampler);
    return runtime;
  }

  /**
   * л””лІ„к№… м •ліҙ
   */
  debug_info(): string {
    return (
      `PostMindLangRuntime:\n` +
      `  ${this.encoder.debug_info()}\n` +
      `  ${this.paths.debug_info()}\n` +
      `  ${this.ensemble.debug_info()}\n` +
      `  ${this.sampler.debug_info()}\n` +
      `Stats:\n` +
      `  Total Executions: ${this.stats.total_executions}\n` +
      `  Total Refinements: ${this.stats.total_refinements}\n` +
      `  Avg Confidence: ${this.stats.avg_confidence.toFixed(4)}\n` +
      `  Avg Iterations: ${this.stats.avg_iterations.toFixed(2)}`
    );
  }

  /**
   * лҹ°нғҖмһ„ мғҒнғң нҷ•мқё
   */
  health_check(): {
    encoder: boolean;
    paths: boolean;
    ensemble: boolean;
    sampler: boolean;
    overall: boolean;
  } {
    const tests = {
      encoder: true,
      paths: true,
      ensemble: true,
      sampler: true,
    };

    try {
      // мқёмҪ”лҚ” н…ҢмҠӨнҠё
      const q = TensorOps.randn(this.config.query_dim);
      const z = this.encoder.encode(q);
      tests.encoder = z.length === this.config.encoder_dim;

      // кІҪлЎң н…ҢмҠӨнҠё
      const { z_a, z_b, z_c } = this.paths.execute_parallel(z);
      tests.paths =
        z_a.length === this.config.path_dim &&
        z_b.length === this.config.path_dim &&
        z_c.length === this.config.path_dim;

      // м•ҷмғҒлё” н…ҢмҠӨнҠё
      const w = this.ensemble.compute_weights(q);
      tests.ensemble =
        w.length === 3 && Math.abs(TensorOps.sum(w) - 1.0) < 1e-6;

      // мғҳн”Ңлҹ¬ н…ҢмҠӨнҠё
      const e = this.ensemble.combine(w, z_a, z_b, z_c);
      const sample = this.sampler.sample(e);
      tests.sampler =
        sample.token >= 0 && sample.token < this.config.vocab_size;
    } catch (e) {
      return {
        encoder: false,
        paths: false,
        ensemble: false,
        sampler: false,
        overall: false,
      };
    }

    return {
      ...tests,
      overall: Object.values(tests).every((v) => v),
    };
  }
}

